  source_url = excluded.source_url,
  updated_at = now();

-- ── JASC codes (547 rows) ─────────────────────────────────────────────────
INSERT INTO jasc_codes (
  jasc_code, ata_code, title, definition, source, source_version, source_url,
  status, applicable_fixed_wing, applicable_rotorcraft, applicable_piston,
  applicable_turbine, applicable_jet, applicable_turboprop,
  applicable_single_engine, applicable_multi_engine, system_level, wiring_code, notes
) VALUES
  ('1100', '11', 'Placards and Markings', 'For reports on all placards, decals, and markings installed by the manufacturer including those required by government regulations. The report should include the system or component involved. The aircraft make and model is required. The location of the item is essential for a meaningful report. Such information should be extracted from the text and entered in the proper data fields (Example: Item = placard; location = entrance door; part condition = missing. Text= the "closed and locked" decal is missing from the main passenger entrance door).', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('1210', '12', 'Fuel Servicing', 'For reports indicating a problem relating to any type of aviation fuel. The general instructions are not applicable to any particular system.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('1220', '12', 'Oil Servicing', 'For reports indicating a problem relating to aviation lubricating oil. The general instructions are not applicable to any particular system.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('1230', '12', 'Hydraulic Fluid Servicing', 'For reports which indicate a problem with any type of hydraulic fluid. The general instructions are not applicable to any particular system.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('1240', '12', 'Coolant Servicing', 'For reports indicating a problem with any type of engine coolant used in aircraft. The general instructions are not applicable to any particular system.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('1400', '14', 'Miscellaneous Hardware', 'For miscellaneous parts that are not associated with an installed aircraft component or system. Use this code when there is insufficient information to file in a more specific JASC 1400 series code.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('1410', '14', 'Hoses and Tubes', 'For reports indicating a problem with any aircraft or engine hose or that are not associated a specific aircraft system.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('1420', '14', 'Electrical Connectors', 'For reports indicating a problem with any aircraft or engine electrical connector that is not associated a specific aircraft system.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('1430', '14', 'Fasteners', 'For reports indicating a problem with any aircraft or engine fastener that is not associated a specific aircraft system. Typical parts are generic AN bolts, nuts, rivets, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('1497', '14', 'Miscellaneous Wiring', 'For reports indicating a problem with any aircraft or engine wiring that is not associated a specific aircraft system.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('1800', '18', 'Helicopter Vibration/Noise Analysis', 'The units and components enabling operators to monitor and diagnose vibration and noise levels in order to identify imbalance, damage, or misalignment in helicopter components.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('1810', '18', 'Helicopter Vibration Analysis', 'For reports of equipment necessary to monitor, measure, diagnose, and locate sources of vibration in dynamic and structural components.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('1820', '18', 'Helicopter Noise Vibration', 'For reports of equipment necessary to monitor, measure, diagnose and locate sources of noise in dynamic and structural components.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('1897', '18', 'Helicopter Vibration System Wiring', 'For reports indicating a problem with wiring used on equipment necessary to monitor, measure, diagnose and locate sources of noise in dynamic and structural components. AIRFRAME SYSTEMS', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2100', '21', 'Air Conditioning System', 'For miscellaneous parts that cannot be associated with specific air conditioning, pressurization, or distribution codes. Examples are lines, hoses, etc., with no reference to the specific using system on the incoming report. Also, for those units and components furnishing a means of pressurizing, heating, cooling, moisture controlling, filtering, and treating the air used to ventilate areas of the fuselage within the pressure vessel.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2110', '21', 'Cabin Compressor System', 'The system and its controls supplying compressed air to the cabin. For reported problems with the compressor unit and not the associated system. Related entries should include the component manufacturer''s make, model, and the specific defective part by name and part number. Typical parts are controls and indicating systems related to the compressors, wiring, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2120', '21', 'Air Distribution System', 'The system used to induct and distribute air. Does not include valves that are a part of the temperature control, pressurization, or the distribution fan. Typical parts are equipment rack cooling systems, ozone converters, scoops, ducting, inlets, check valves, wiring, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2121', '21', 'Air Distribution Fan', 'For reports pertaining to the fan/blower including associated motor which distributes air within the confine for comfort or equipment cooling. Typical parts are bearing, bushing, motor, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2130', '21', 'Cabin Pressure Control System', 'For reports of miscellaneous system components or parts other than the controller, indicator, sensor, regulator, or outflow valves. Typical parts are amplifier, switch, electrical connector, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2131', '21', 'Cabin Pressure Controller', 'For the reports pertaining to the controller units only and not for the system. The defective part should be identified by the part name and part number whenever possible.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2132', '21', 'Cabin Pressure Indicator', 'For reports of the cabin pressurization system, pressure indicators, and associated system parts.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2133', '21', 'Pressure Regulator/Outflow Valve', 'For reports of outflow/dump valves and associated parts such as linkage, filter, diaphragm, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2134', '21', 'Cabin Pressure Sensor', 'The units and systems, which measure differential, pressure and transmit a signal. Typical parts are pressure switch, transducer, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2140', '21', 'Heating System', 'The units and systems supplying heated air to the cockpit or cabin. Includes the heat source (heater), controlling aspects, and temperature sensors/indicators. Typical parts are fuel pump, filter, plumbing, circuitry, relay, heat exchanger, igniter, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2150', '21', 'Cabin Cooling System', 'The units and systems supplying cooled air to the cockpit or cabin. Does not include the temperature control and indicating system. Typical parts are flow valve, relay, condenser, ram air sensor, heat exchanger, cooling turbine, air cycle machine, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2160', '21', 'Cabin Temperature Control System', 'The units and circuitry other than the control unit which are used for controlling the temperature of the air in the cockpit and cabin. Typical parts are control valves, thermal sensing devices, switches, amplifiers, and wiring.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2161', '21', 'Cabin Temperature Controller', 'For reports of the parts within the cabin temperature control unit. A typical entry would only reference the "control unit" if specific part numbers are not available.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2162', '21', 'Cabin Temperature Indicator', 'For reports of the indicators, lamps and associated circuitry which indicates the air temperature in the cabin.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2163', '21', 'Cabin Temperature Sensor', 'For reports of the sensors and associated circuitry sensing the temperature of the air in the cabin and relays a signal to the indicator.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2170', '21', 'Humidity Control System', 'For reports of system parts that control humidity. Typical parts are bag, sock, filter, moisture separator, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2197', '21', 'Air Conditioning System Wiring', 'For reports indicating a problem with wiring specific to the Air Conditioning System.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2200', '22', 'Auto Flight System', 'The units and components that furnish a means of automatically controlling flight of the aircraft. Includes those units and components controlling direction, heading, attitude, altitude, and speed. Use this code when there is insufficient information to file in a more specific JASC 2200 series code.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2210', '22', 'Autopilot System', 'For reports of miscellaneous parts associated with the autopilot system used for controlling attitude and direction. Typical parts are yaw damper, cable, switch, sensor, relay, etc. The major components such as computer, servo, and controller are to be filed in the specific JASC 2200 series code.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2211', '22', 'Autopilot Computer', 'For reports pertaining to the autopilot computer only. Typical parts are resistor, circuit board, capacitor, or power supply, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2212', '22', 'Altitude Controller', 'The units transmitting output information signals to automatically maintain a predetermined altitude, rate of climb, or descent. Does not include the connecting system parts such as the sensor switch. The controller make and model should be included.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2213', '22', 'Flight Controller', 'The command unit of an autopilot system. It is manually operated to generate signals which cause the aircraft to climb, dive, or perform coordinated turns. The controller make and model should be included.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2214', '22', 'Autopilot Trim Indicator', 'The instrument and associated circuitry that indicates the trim position selected by the pilot.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2215', '22', 'Autopilot Main Servo', 'The unit mechanically connected to primary flight control actuating mechanisms, which is used to mechanically reposition control surfaces in accordance with electrical or pneumatic signals from a controller.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2216', '22', 'Autopilot Trim Servo', 'The units mechanically connected to flight control cables, etc., for making minor corrections in aircraft attitude or direction.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2220', '22', 'Speed-Attitude Correction System', 'The system which automatically maintains safe flight conditions by correcting for effects of speed and out-of-trim conditions by such means as automatic trim, mach trim, or speed stability and mach feel. This includes sensing, computing, actuating, indicating, internal monitoring, warning devices, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2230', '22', 'Auto Throttle System', 'The system that automatically controls the position of the throttles to properly manage engine power during all phases of flight/attitude. This includes engaging, sensing, computing, amplifying, controlling, actuating and warning devices. Typical parts are amplifiers, computers, servos, limit switches, clutches, gearboxes, warning lights, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2250', '22', 'Aerodynamic Load Alleviating', 'The system that automatically corrects and provides for gust loading/upset, aerodynamic augmentation, alleviation, suppression, ride control, etc. This includes sensing, computing, actuating, indicating, internal monitoring, warning devices, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2297', '22', 'Auto Flight System Wiring', 'For reports indicating a problem with wiring specific to the Autoflight/Auto Pilot System.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2300', '23', 'Communications System', 'The units and components furnishing a means of communicating from one part of the aircraft to another and between the aircraft or ground stations, includes voice, data, continuous wave (C-W) communicating components, passenger announcement systems, intercom, inflight telephones, and tape reproducers-record player. Use this code when insufficient information is reported to file in a more specific JASC 2300 series code. Also for reports of units or parts common to more than one communication system.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2310', '23', 'HF Communications System', 'The system parts and circuitry including the receiver, transmitter, and antenna used exclusively in the high frequency (HF) communications.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2311', '23', 'UHF Communications System', 'The system parts and circuitry including the receiver, transmitter, and antenna used exclusively for ultra high frequency (UHF) communications.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2312', '23', 'VHF Communications System', 'The system parts and circuitry including the receiver, transmitter, and antenna used exclusively for very high frequency (VHF) communications.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2320', '23', 'Data Transmission Auto Call', 'The system components and parts which presents data derived from pulse coded transmissions. Includes "selective calling" (SELCAL), "aircraft communications addressing and reporting system" (ACARS), teleprinter, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2330', '23', 'Entertainment System', 'For reports on passenger entertainment system or components such as amplifier, cassette recorder player, control panel, speaker, video equipment, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2340', '23', 'Interphone/Passenger Announcement (PA) System', 'For reports on the interphone/passenger announcement (PA) system, including the amplifier used for communication by flight and ground personnel to communicate between areas on the aircraft.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2350', '23', 'Audio Integrating System', 'For reports of the system components and parts including the control panel and amplifier which controls output of communications and navigation receivers into flight crew headphones and speakers. Also includes output from microphones into communications transmitters. Typical parts are microphones, cockpit speakers, and headphones, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2360', '23', 'Static Discharge System', 'The parts dissipating static electricity. Does not include bonding straps on engine or airframe used to assure paths for DC current, which are filed in JASC code 2430. Typical parts are wick, bonding strap, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2370', '23', 'Audio/Video Monitoring', 'For reports on installations that record or monitor crew or passenger conversation or movement for security or safety purposes. Includes voice recorder, television, monitor, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2397', '23', 'Communications System Wiring', 'For reports indicating a problem with wiring specific to the Communications Systems.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2400', '24', 'Electrical Power System', 'The electrical units and components that generate, control, and supply AC/DC electrical power for other systems through the secondary busses. For reports on electric power generating system parts and circuitry other than major components reported with insufficient information to file in a specific JASC 2400 series code. Typical parts are circuit breaker, relay, connector, resistor, wire bundles, switches, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2410', '24', 'Alternator-Generator Drive', 'For reports on alternator and generator drives mounted on reciprocating "opposed" type engines. Does not include alternator cases. Typical parts are bracket, pulley, belt, link, idler pulley, bolt, drive shaft and gears that stay with the alternator. Also for reports on constant speed drive (CSD) unit mounted on turbine engines to drive alternating current (AC) producing alternators at a predetermined and constant RPM. Typical parts are shaft seal, shaft, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2420', '24', 'AC Generation System', 'For reports of system parts other than the alternator, regulator, AC inverter or phase adapter generating an alternating current for aircraft which incorporate an alternating current electrical system. Used primarily with large, turbine engine powered aircraft. Does not include the using systems.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2421', '24', 'AC Generator-Alternator', 'The engine driven component that generates alternating current (AC) for aircraft with AC electrical systems. Does not include AC alternators on light piston-engine power aircraft with direct current (DC) electrical systems. Does not include single units used for both engine starting and electric power generating. Typical parts are bearing, shaft, housing, and integrated drive generator (IDG) which contains both AC and DC generators.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2422', '24', 'AC Inverter', 'The component which converts direct current to alternating current.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2423', '24', 'Phase Adapter', 'The component used to change the alternating current (AC) phase of output for specific using equipment.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2424', '24', 'AC Regulator', 'The component that regulates the AC voltage from the alternator-generator to maintain a set voltage output for the using systems (i.e., generator control unit).', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2425', '24', 'AC Indicating System', 'The equipment indicating, voltage, current flow, and system faults in the AC power systems.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2430', '24', 'DC Generating System', 'The system parts and circuitry other than the generator/alternator and DC generation system regulator used to generate a direct current (DC); or from an alternator, the output of which is rectified to DC. Typical parts are relay, switch, connector, terminal, sensor, reverse current relay, etc. Such systems are more prevalent on light single and twin-engine aircraft.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2431', '24', 'Battery Overheat Warning System', 'The system parts that sense and warn/indicate of a battery overtemperature condition. Typical parts are sensor, lamp, gauge, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2432', '24', 'Battery/Charger System', 'The component providing a source of DC voltage and current flow independent of rotating generators and alternators. Typical parts are battery charger, cell, case, post, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2433', '24', 'DC Rectifier/Converter', 'The component which converts AC current for the using systems.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2434', '24', 'DC Generator-Alternator', 'The engine driven component generating a direct current (DC) or a rectified alternating current for aircraft with DC electrical systems. For reports of alternators on light aircraft with piston engines. Does not include mounting brackets, drive belts and pulleys external to the unit. Typical parts are bearing, housing, coupling, fan, capacitor, drive, brush, seal, clutch, armature and bell, shaft, field winding, case bolt, ground stud, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2435', '24', 'Starter-Generator', 'The single component used for both engine starting and direct current generation on turbine engines. Typical parts are bearing, shaft, brush, fan, retainer ring, armature, brush, housing, end bell, terminal, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2436', '24', 'DC Regulator', 'The component that regulates direct current voltage from a generator or alternator.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2437', '24', 'DC Indicating System', 'The equipment indicating voltage, current flow, and system faults in the DC power systems.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2440', '24', 'External Power System', 'The electrical system within the aircraft which is used to connect external power to the aircraft''s electrical system. Does not include the external power supply units. Typical parts are receptacle, switch, indicator lamp, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2450', '24', 'AC Power Distribution System', 'The electrical system providing for connection of AC power to using systems. Does not include the using system. Typical parts are main and secondary system buss, circuit breaker, limiter, jumper, load meter switch, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2460', '24', 'DC Power Distribution System', 'The electrical system which provides for connection of DC power to using systems. Does not include using system. Typical parts are main and secondary system buss, circuit breaker, buss tie breaker, limiter, jumper, load motor switch, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2497', '24', 'Electrical Power System Wiring', 'For reports indicating a problem with wiring specific to the Electrical Power Systems not reportable in the Power Distribution Systems.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2500', '25', 'Cabin Equipment/Furnishings', 'The removable items of equipment and furnishings mounted or contained in the flight, passenger, cargo, accessory compartments, and areas described in other JASC 2500 series codes shown below. Does not include structure or equipment assigned specifically to other JASC codes.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2510', '25', 'Flight Compartment Equipment', 'The removable equipment and furnishings within the cockpit or crew station of a general nature and not specifically covered in other JASC 2500 series codes. Typical parts are seats, shoulder harnesses, take-up harness reels, seat belts, sun visors, panels, map case, attach brackets and hardware, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2520', '25', 'Passenger Compartment Equipment', 'The removable equipment and furnishings within the cabin of a general nature and not specifically covered in other JASC codes. Typical parts are seats, seat belts, hat rack, coat closet, panel, including passenger comfort items such as personal blankets, pillows, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2530', '25', 'Buffet/Galleys', 'For reports pertaining to any of the galley equipment. Typical parts are hot plate, coffeepot, food carts, ovens, tray, pad, relay, switch, connector, dispenser, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2540', '25', 'Lavatories', 'The units and associated systems and parts located in lavatories. Does not include wash basins and other waste disposal items in JASC code 3830. Typical parts are trash containers, dispensers, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2550', '25', 'Cargo Compartments', 'The compartments for the storage of baggage and cargo including external mounted pods. Does not include the exterior door, hinges and latches which are filed in JASC code 5230. Typical parts are tie downs, restraint nets, and equipment for loading and unloading cargo (includes external load handling equipment).', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2551', '25', 'Agricultural Spray System', 'For reports of aerial application equipment such as hopper, tank, spray nozzle, boom, pump, bracket, valve.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2560', '25', 'Emergency Equipment', 'The components, parts, and systems carried for emergency use other than those specifically referenced in other JASC 2500 series codes. Does not include fire extinguishes, oxygen equipment, and flashlight. Flashlights are filed under JASC code 3350. Escape slide girt bars are filed under this code.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2561', '25', 'Life Jacket', 'For reports of defective parts of life jackets used for flotation of individual persons. Include the life jacket make and model in the report if available.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2562', '25', 'Emergency Locator Beacon', 'The components transmitting an electronic signal on an emergency frequency to assist in locating a crashed aircraft. Typical parts are impact switch, antenna, battery pack, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2563', '25', 'Parachute', 'For the reporting of defective parts of parachutes used for reducing landing roll distance as well as for personnel jumping. The parachute make and model is beneficial if available.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2564', '25', 'Life Raft', 'The inflatable component which provides emergency flotation for two or more persons in event of ditching in water. Typical parts are bottle, valve, oral pump, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2565', '25', 'Escape Slide', 'The inflatable component which enables rapid evacuation from an aircraft cabin to ground level during emergencies on the ground. The slide should be identified by make and model if possible and should include location. Typical parts are valve, bottle, inflation handle, mount brackets, door, latch, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2570', '25', 'Accessory Compartment', 'The compartments for the housing of various components or accessories with insufficient information to file in a more specific JASC 2500 series code.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2571', '25', 'Battery Box Structure', 'The structure supporting, vents, and provides overboard draining for aircraft batteries. Typical parts are vent cap, drain tube, insulator, cover, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2572', '25', 'Electronic Shelf Section', 'The shelves and attaching parts supporting the electronic equipment within the fuselage. Does not include the equipment used for equipment cooling such as fans, and blower motors.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2597', '25', 'Equipment/Furnishings Wiring', 'For reports indicating a problem with wiring specific to the Equipment/Furnishing Systems.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2600', '26', 'Fire Protection System', 'The fixed and portable units and components which detect and indicate fire or smoke, and store and distribute fire extinguishing agent to all protected areas of the aircraft. For reports of a general nature with insufficient information to file in a more specific JASC 2600 series code.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2610', '26', 'Detection System', 'The system used to sense and indicate the presence of overheat or fire in all protected areas. Reporting the specific location of the defective part is essential. Use this code when there is insufficient information to file in a more specific JASC 2610 series code.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2611', '26', 'Smoke Detection', 'The system used to sense and indicate the presence of smoke in all protected areas of the aircraft. Reporting the specific location of a defective part is essential. Typical parts are detector, sensor, wiring, relay, amplifier, test circuit, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2612', '26', 'Fire Detection', 'The system used to sense and indicate the presence of fire in all protected areas of the aircraft. Typical parts are detector, sensor, wiring, relay, amplifier, test circuit, etc. Reporting the specific location of a defective part is essential.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2613', '26', 'Overheat Detection', 'The system used to sense and indicate the presence of an overheat condition in all protected areas of the aircraft. Reporting the specific location of a defective part is essential. Typical parts are detector, sensor, wiring, relay, amplifier, test circuit, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2620', '26', 'Extinguishing System', 'For reports of the components and parts other than the fixed or portable bottles used to extinguish fire. Typical parts are valve, squib, control module, switch, tubing, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2621', '26', 'Fire Bottle, Fixed', 'The fixed fire bottle and associated parts that store extinguishing agent under pressure. Typical parts are bottle, cartridge, and bracket.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2622', '26', 'Fire Bottle, Portable', 'The portable fire extinguishes mounted within the flight compartment and cabin.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2697', '26', 'Fire Protection System Wiring', 'For reports indicating a problem with wiring specific to the Fire Protection System.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2700', '27', 'Flight Control System', 'The units and components furnishing a means of manually controlling the flight attitude characteristics of the aircraft. Also includes the functioning and maintenance aspects of the flaps, spoilers and other control surfaces, but does not include the structure, which is covered in the Structures JASC Chapters 55 or 57. Use this code for reports of flight control problems of a general nature involving two or more systems, or that contain insufficient information to file in a more specific JASC 2700 series code. An example would be a cable defect reported without reference to the using system or an interconnect between two systems. Does not include rotorcraft flight controls, which are covered in the JASC Rotor Chapter 67. Typical parts are hydraulic boost system, controls, mounting brackets, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2701', '27', 'Control Column Section', 'The component and associated parts mounted onto the control wheel, which transmits motion from the cockpit to connecting cables, pushrods, etc., to actuate the aileron and elevator, stabilator, ruddervator control surfaces. Includes control sticks in aircraft not equipped with control wheels. Typical parts are bearing, socket, guide, bushing, pulley bracket, sprocket, chain, stops, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2710', '27', 'Aileron Control System', 'The system components and parts from the control column to the aileron surface that cause actuation (deflection). Includes manual and power assisted systems but does not include the autopilot actuation mechanism which is filed in JASC Chapter 22. Also includes brackets for the support or attachment of pulleys, pushrods, and bellcranks. Does not include control surface hinges or structure filed in JASC code 5700. Typical parts are actuator, valve, rod end, pulley, cable, bellcrank, turnbuckle, stops, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2711', '27', 'Aileron Tab Control System', 'The system components and parts controlling movement and position of the trim tab on the aileron. Includes the cockpit control. Typical parts are jackscrew, cable, pulley, turnbuckle, stops, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2720', '27', 'Rudder Control System', 'The system components and parts from the cockpit pedals to the rudder surface which cause movement. Includes manual and power assisted systems other than the actuator and autopilot actuating mechanism. Also includes brackets for the support or attachment of pulleys, pushrods, and bellcranks. Does not include control surface hinges or structure (filed in JASC code 5540) or the yaw dampers (filed in JASC code 2210). Typical parts are cable, rod end, turnbuckle, bolt, pedal, spring, torque tube, control valve, stops, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2721', '27', 'Rudder Tab Control System', 'The system components and parts of the rudder trim control system, from the cockpit control to the rudder that causes deflection. Does not include hinges or structure, which are filed in JASC code 5543, or the yaw dampers, which are filed in JASC code 2210. Typical parts are actuator, actuator bracket, cable, pulley, chain, rod end, bellcrank, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2722', '27', 'Rudder Actuator', 'The system components and parts which actuate the rudder. Typical parts are motor, actuator, actuator bracket, jackscrew, rod-end, seals, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2730', '27', 'Elevator Control System', 'The system components and parts including actuator from the control column to the elevators that cause movement. Includes control-actuating mechanism for "ruddervators" installed on "V" tail aircraft. Does not include hinges, structure, and balance weights filed in JASC code 5520, or the autopilot servo in JASC code 2216. Typical parts are torque tube, cable, rod end, stops, actuator, feel computer, bracket, control valve, bob weight, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2731', '27', 'Elevator Tab Control System', 'The system components and parts from the cockpit trim control to the elevator, ruddervator or stabilator tab, which controls position and movement. Includes the manual and electrical trim system parts. Does not include the hinges or structure, which are filed in JASC code 5520, the balance weights in JASC code 5520, or the autopilot servo in JASC code 2216. Typical parts are jackscrew, cable, actuator, sensor, motor, chain, sprocket, indicator, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2740', '27', 'Stabilizer Control System', 'The system components and parts from the cockpit control to the stabilizer, except the actuator which controls position of the horizontal stabilizer for pitch trim (usually found on high performance turbine powered aircraft). Also for stabilator control systems on aircraft utilizing a single horizontal tail surface for both the stabilizer and elevator. Does not include structure in JASC code 5511. Typical parts are cable, bellcrank, pulley, control valve, indicator, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2741', '27', 'Stabilizer Position Indicating', 'The system components and parts that sense, transmit, and indicate relative position of movable stabilizers for purpose of pitch trim. Typical parts are indicators, transmitters, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2742', '27', 'Stabilizer Actuator', 'The component which actuates the horizontal stabilizer to infinite angles of incidence to provide pitch trim. Includes both manual and power assist types. Typical parts are actuator, actuator bracket, clutch, motor, seal, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2750', '27', 'Trailing Edge Flap Control System', 'The system components and parts, except the actuator and position indicator which controls position and movement of wing trailing edge flaps. Does not include the structure, carriage, fittings, tracks and rollers which are filed in JASC code 5753; or the motor or actuator which causes movement of the flaps and are filed in JASC code 2752. Typical parts are control valve, switch, flow limiter, cable, torque tube, transmission, jackscrew, bypass valve, limit switch, return spring, buss cable, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2751', '27', 'Trailing Flap Position Indicating System', 'The system components and parts that sense, transmit and indicate trailing edge flap position relative to the wing surface. Typical parts are indicator, transmitter, position module, asymmetry switch, and comparator, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2752', '27', 'Trailing Edge Flap Actuator', 'The component which actuates the trailing edge flaps. Typical parts are motor, actuator, seal, jackscrew, rod end, actuator support fittings, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2760', '27', 'Drag Control System', 'The system components and parts other than actuator which controls position, movement, and indicate relative position of drag device and variable aerodynamic surfaces on the wing includes speed brake systems. Does not include structure and hinges filed in JASC code 5755. Typical parts are valve, hose, push rod, line, cable, indicator.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2761', '27', 'Drag Control Actuator', 'The components that actuates spoiler and speed brake surfaces on the wing for speed and lift reducing purposes. Typical parts are seal, rod end bearing, rod end, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2770', '27', 'Gust Lock Damper System', 'The system and components protecting flight control surfaces from movement and damage by wind gusts while the aircraft is on the ground. Includes cockpit controlled surface locks common in light aircraft and independent hydraulic gust damper units mounted at each flight control surface on large jet powered aircraft. Does not include the dampening feature of the flight control power boost systems, which are filed with the specific control system (i.e., rudder damper). Typical parts are damper, cylinder, seal, rod end, lock pin cable, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2780', '27', 'Leading Edge Slat Control System', 'The system components and parts except the actuator and position indicating system that controls the position and movement of the wing leading edge devices used for lift augmenting. Does not include the structure, hinges, and parts that do not cause movement of the surface filed in JASC code 5754. Typical parts are leading edge flaps, variable opening wing slots, priority valve, switch, cable, pulley, actuator bracket, torque shaft, regulator, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2781', '27', 'Leading Edge Slat Position Indicating System', 'The transmitter, indicator, warning lamps, and associated circuitry providing relative position information of wing leading edge devices to the flight crew.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2782', '27', 'Leading Edge Slat Actuator', 'The component causing movement of the wing leading edge device control surfaces. Does not include related system or position indicating. Typical parts are actuator, actuator bracket, seal, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2797', '27', 'Flight Control System Wiring', 'For reports indicating a problem with wiring specific to the Flight Control Systems.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2800', '28', 'Aircraft Fuel System', 'The units and components storing and delivering fuel to the engine. Includes the integral tank leak detection and sealing. Does not include the structure of integral, tip fuel tanks, fuel cell backing boards covered in the structures JASC Chapters 53 and 57, or the fuel flow rate sensing, transmitting, or indicating systems which are covered in JASC Chapter 73. Use this code for fuel system reports with insufficient information to file in a more specific JASC 2800 series code. This code is also used to report problems involving two or more aircraft fuel system JASC codes.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2810', '28', 'Fuel Storage', 'The portion of the fuel system used for the storage of fuel. Does not include defects in the wing primary structure of integral tanks. Typical parts are removable metal tank, tip tank, header tank, bladder fuel cell, tank interconnect lines, vent line, vent valve, drain valve, filler cap, filler neck, check valve, vent tube, cap seal, filler adapter, outlet fitting, screen, fueling panel, tank strap, sealant, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2820', '28', 'Aircraft Fuel Distribution System', 'The portion of the aircraft fuel system other than selector valves, transfer valves, electric motor driven pumps used to distribute fuel from the tank outlet to the powerplant quick disconnect or up to the strainer unit. Includes the engine primer equipment, the switch that senses failure of a system pump, and the switch that automatically activates the boost pump. Typical parts are line, fitting, primer, nozzle, primer pump, actuating linkage for the fuel selector/shutoff valve, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2821', '28', 'Aircraft Fuel Filter/Strainer', 'The component that filters unmetered fuel upstream of the engine fuel control/carburetor. Does not include the engine fuel metered control system filters (filed in JASC code 7300). Typical parts are screen, housing, bowl, gasket, plunger, stand pipe, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2822', '28', 'Fuel Boost Pump', 'The electric motor/engine driven pumps providing fuel under pressure to the engine fuel control/carburetor for starting and emergency use. Includes parts of the pump, associated motor, and electrical circuitry/switch. Does not include pressure switch indicating system. Typical parts are housing, seal, motor, brush, bearing, connector, and fuel transfer pump, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2823', '28', 'Fuel Selector/Shut-Off Valve', 'The component and associated controls and position indication units which provides for specific tank selection or shutting off flow to the engine. Typical parts are housing, rotor, handle, guard, seat, seal, selector valve, shutoff valve, spring, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2824', '28', 'Fuel Transfer Valve', 'The component and associated control linkage which provides for the transfer of fuel between tanks for crossfeeding to alternate engine fuel systems. Typical parts are, seal, housing, rotor, handle, transfer valve, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2830', '28', 'Fuel Dump System', 'The system and components that provide for the jettison of fuel overboard during flight. Typical parts are valve, switch, dump chute, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2840', '28', 'Fuel Indicating System', 'For general reports pertaining to the aircraft fuel indicating systems, but with no specific reference to the transmitter (tank unit) or indicator. Does not include engine fuel pressure reports, which are filed in JASC code 7332, or flow indication system in JASC code 7331. Typical parts are circuit breaker, connector, pressure switch, indicator lights, dripstick, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2841', '28', 'Fuel Quantity Indicator', 'The indicator and low level warning system used to indicate the quantity of fuel in the tanks. Typical parts are indicator, lamp, bulb, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2842', '28', 'Fuel Quantity Sensor', 'The tank unit which measures and transmits a quantity level signal to the cockpit indicator. Typical parts are transmitter, float switch, probe, sensor, totalizer, tank unit float, gasket, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2843', '28', 'Fuel Temperature Indicator', 'The tank unit which measures the temperature of fuel in the tanks.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2844', '28', 'Fuel Pressure Indicator', 'The tank unit which measures the pressure of fuel in the tanks. Typical parts are the pressure switch and indicator lights, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2897', '28', 'Fuel System Wiring', 'For reports indicating a problem with wiring specific to the Fuel System.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2900', '29', 'Hydraulic Power System', 'The units and components that furnish hydraulic fluid under pressure to a common point (manifold) for re-distribution to other defined systems. For miscellaneous system parts other than components listed under other specific JASC Chapter 29 codes. Also, for reports of units or parts common to two or more components.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2910', '29', 'Hydraulic System, Main', 'The portion of the main system which is used to store and deliver hydraulic fluid to the using system. Includes all hydraulic systems other than those designated emergency or standby. Does not include the supply valves to the using systems. Typical parts are tanks, accumulators, valves, pumps, levers, cables, line, hose, relief, shutoff vales, check valves, wiring, switches, external connectors, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2911', '29', 'Hydraulic Power Accumulator, Main', 'The component that provides for pressure surges to maintain a constant pressure in the system. Typical parts are accumulator, seal, end cap, air valve, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2912', '29', 'Hydraulic Filter, Main', 'The component which filters sediment from the hydraulic fluid in the main system. Typical parts are seal, gasket, housing, element, packing, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2913', '29', 'Hydraulic Pump (Electric/Engine), Main', 'The component that provides hydraulic fluid pressure to using systems but does not include the using systems. Includes power packs incorporating integral pumps, electric motors, and solenoids used in certain light aircraft models. Also includes pumps such as those used in flight control systems on large aircraft. Typical parts are pump, motor, shaft, brush, solenoid, case, power pack, seal, switch, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2914', '29', 'Hydraulic Handpump, Main', 'The manually actuated pump for emergency system pressure. Typical parts are handle, lever, seal, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2915', '29', 'Hydraulic Pressure Relief Valve, Main', 'The unit which relieves system relief pressure at a preset pressure. Typical parts are seal, spring, housing, relief valve, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2916', '29', 'Hydraulic Reservoir, Main', 'The component which stores hydraulic fluid. Typical parts are reservoir, filler cap, filler neck, sight gauge, seal, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2917', '29', 'Hydraulic Pressure Regulator, Main', 'The unit that maintains a preset operating system pressure to the using systems. Typical parts are regulator, seal, case, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2920', '29', 'Hydraulic System, Auxiliary', 'The portion of the main system which is classified as auxiliary, emergency, or standby, and which is used to supplement or take the place of the main hydraulic fluid to the using system. Does not include the supply valves to the using systems. Typical parts are tank, accumulator, valve, pump, lever, cables, switch, plumbing, wiring, external connectors, and miscellaneous auxiliary system parts other than those listed in JASC codes 2921 through 2934.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2921', '29', 'Hydraulic Accumulator, Auxiliary', 'The component which provides for pressure surge to maintain a constant pressure in the auxiliary system. Typical parts are accumulator, seal, end cap and air valve, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2922', '29', 'Hydraulic Filter, Auxiliary', 'The component which filters sediment from the hydraulic fluid in the auxiliary system. Typical parts are seal, gasket, housing, element, and packing, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2923', '29', 'Hydraulic Pump, Auxiliary', 'The component which provides hydraulic fluid pressure to the using auxiliary system. Typical parts are pump, motor, shaft, brushes, case, seal, switches, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2925', '29', 'Hydraulic Pressure Relief, Auxiliary', 'The unit which relieves auxiliary system pressure. Typical parts are seal, spring, housing, relief valve, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2926', '29', 'Hydraulic Reservoir, Auxiliary', 'The unit which stores auxiliary hydraulic fluid. Typical parts are reservoir, filler cap, filler neck, sight gauge, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2927', '29', 'Hydraulic Pressure Regulator, Auxiliary', 'The unit that maintains a preset operating system pressure to the using auxiliary hydraulic system. Typical parts are regulator, seal, case, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2930', '29', 'Hydraulic Indicating System', 'For reports of hydraulic pressure and quantity indicating system parts other than the indicator or sensor or for parts common to both pressure and quantity systems.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2931', '29', 'Hydraulic Pressure Indicator', 'The instrument and associated low pressure warning system that registers system pressure. Typical parts are indicator, warn lamp, bulb, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2932', '29', 'Hydraulic Pressure Sensor', 'The components that sense system pressure and transmit a signal to the cockpit indicator or low pressure warning lamp. Typical parts are transmitter, pressure switch, sensor, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2933', '29', 'Hydraulic Quantity Indicator', 'The instrument and associated low level warning system which registers reservoir fluid quantity. Typical parts are indicator, lamp, bulb, sight gage, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2934', '29', 'Hydraulic Quantity Sensor', 'The components that sense the fluid level and low level warning and transmit a signal to the quantity indicator. Typical parts are transmitter, sensor, float switch, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('2997', '29', 'Hydraulic Power System Wiring', 'For reports indicating a problem with wiring specific to the Hydraulic Power System.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3000', '30', 'Ice/Rain Protection System', 'The units and components which provide a means of preventing or disposing of formation of ice and rain on various parts of the aircraft. Includes miscellaneous items with insufficient information to file in a specific JASC 3000 series code. Does not include the basic windshield panel.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3010', '30', 'Airfoil Anti/De-ice System', 'The system components and parts including the boots, which provide for wing and empennage leading edge ice prevention or removal. Does not include ducts upstream of the airfoil control/selector valves. Typical parts are timer, valve, switch, hose, flow valve, duct, duct coupling, thermostat, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3020', '30', 'Air Intake Anti/De-Ice System', 'The system and components that eliminate or prevent the formation of ice in or around air intakes such as turbine engine cowling. Does not include engine anti-icing reports filed in JASC code 7510. Includes the electrically heated boot at the air intake lips.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3030', '30', 'Pitot/Static Anti-Ice System', 'The heating elements in the pitot-static pick up heads to eliminate or prevent the formation of ice. Does not include defects with the pitot or static systems. Typical parts are element, switch, wiring, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3040', '30', 'Windshield/Door Rain/Ice Removal', 'The system and components which is used to clear, eliminate or prevent the formation of rain, ice or Typical parts are motor, actuator, wiper blade, hydraulic converter, shaft, line, switch, the electrical heating portion of heated glass panels, control units, alcohol deice system lines, tanks, pumps, valves, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3050', '30', 'Antenna/Radome Anti-Ice/De-Ice System', 'The system which is used to eliminate or prevent the formation of ice on antennas and radomes.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3060', '30', 'Propeller/Rotor Anti-Ice/De-Ice System', 'The system components and parts which are used to eliminate or prevent the formation of ice on propellers and rotors. Includes electrically heated systems, and alcohol spray systems. Does not include the system parts on the rotating portion of the propeller which are filed in JASC code 6112 or the heating mats on the rotating portion of the rotor in JASC code 6210 or code 6410. Typical parts are brush block, timer, switch, relay, harness, terminal block, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3070', '30', 'Water Line Anti-Ice System', 'The system that is used for prevention of ice in water supply and drain lines.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3080', '30', 'Ice Detection', 'The system which is used to detect and indicate the formation of ice. Typical parts are panel, detector, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3097', '30', 'Ice/Rain Protection System Wiring', 'For reports indicating a problem with wiring specific to the Ice/Rain Protection System.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3100', '31', 'Indicating/Recording System', 'The pictorial coverage of all instrument panels and controls. Procedural coverage of those systems, which give visual or aural warning of conditions in systems which record, store, or compute data from unrelated systems. Includes the system or units which integrate indicating instruments into a central display system not related to any specific system.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3110', '31', 'Instrument Panel', 'The removable cockpit instrument and control panels. Includes the mounting hardware and shock absorbing devices.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3120', '31', 'Independent Instruments', 'The units which measures time, logs elapsed time of operation, or measures acceleration/deceleration forces. Typical parts are hour meter, pressure switch, line, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3130', '31', 'Data Recorders (Flight/Maintenance)', 'The unit which continuously records critical flight, aircraft and powerplant system data, such as attitude, air speed, altitude, engine power, etc., to be used in the event of a crash. Includes the system and parts that provide a source of power and inputs, from various sources critical to flight, to flight data recorder. Typical parts are spool rod, magazine, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3140', '31', 'Central Computers', 'The systems and components used for computing data from a number of different sources without a preponderance of functions in any one system, for call up on a display. Includes integrated instrument systems such as engine, airplane power and central warning indicators when combined into a central display. Typical parts are "digital core avionic system" (DCAS), "engine indications and crew alerting system" (EICAS), stored checklist, emergency procedures, company regulations, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3150', '31', 'Central Warning', 'The panels and associated circuitry which warn of potential problems in two or more independent or related systems. Warnings can be either audible or visual. Typical parts are annunciator panel, relay, lamp, PC board, diode, throttle microswitch, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3160', '31', 'Central Display', 'The systems and components which give visual display of conditions in unrelated systems.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3170', '31', 'Automatic Data', 'The systems and components used for collating and computing data from unrelated systems and transmitting the same automatically. Includes "aircraft to satellite data relay" (ASDAR) system and components.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3197', '31', 'Instrument System Wiring', 'For reports indicating a problem with wiring specific to the Instrument Systems.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3200', '32', 'Landing Gear System', 'The units and components which furnish a means of supporting and steering the aircraft on the ground or water, and make it possible to retract and store the landing gear in flight. Includes the functioning and maintenance aspects of the landing gear doors, but does not include the door structure, which is covered in JASC Chapter 52. Use this code for general landing gear reports with insufficient information for filing in a more specific JASC 3200 series code.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3201', '32', 'Landing Gear/Wheel Fairing', 'The wheel fairings and attaching parts. Typical parts are bracket, fender, fairing, etc. The fairing location such as "nose wheel" should be shown in the "Part Location" field.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3210', '32', 'Main Landing Gear', 'The miscellaneous parts of the main landing gear system which cannot be directly associated with a specific main gear code, such as attachment, emergency flotation or strut, axle, truck, etc. This code is not to be used for the retraction/extension system or the doors. Landing gear location, left or right should be referenced in the "Part Location" field.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3211', '32', 'Main Landing Gear Attach Section', 'The parts and assemblies, which attach the main landing gear to the airframe, structure. An entry in the "Part Location" field should include a reference to "left or right" gear. Typical parts are fitting, bolt, U- bolt, casting, supports, attaching hardware, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3212', '32', 'Emergency Flotation Section', 'The helicopter inflatable floats and attaching parts which permit emergency landings on water. The float make and model, as well as the aircraft make and model should be included in the report. Typical parts are float valve, hose, bracket, cylinder, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3213', '32', 'Main Landing Gear Strut/Axle/Truck', 'The main landing gear components and parts such as struts, axles, trucks which support the aircraft on the ground or water. Typical parts are shock device, torque link, beam and skid/shock device on rotorcraft.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3220', '32', 'Nose/Tail Landing Gear', 'The miscellaneous parts of the nose or tail gear system which cannot be directly associated with a specific nose/tail gear code such as attachment, struts, axles, etc. This code is not to be used for extension/retraction mechanism, steering/dampening system, or doors.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3221', '32', 'Nose/Tail Landing Gear Attach Section', 'The parts and assemblies that attach the nose/tail gear to the airframe structure. Applicable to fixed or retractable type landing gear.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3222', '32', 'Nose/Tail Landing Gear Strut/Axle', 'The nose gear component parts such as shock struts and axles, which support the aircraft on the ground. Torque links are included but steering/shimmy dampening systems and units are excluded.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3230', '32', 'Landing Gear Retraction/Extension System', 'The miscellaneous parts of the retraction and extension systems other than actuators, and door actuating mechanism. Location, such as nose, right or left main should be referenced in the "Part Location" field unless the defective part is common to all locations. Typical parts are leveling cylinders, centering system, actuator brackets, bungees, emergency extension system parts, uplocks/downlocks, uplock/downlock actuator, drag braces, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3231', '32', 'Landing Gear Door Retract Section', 'The nose and main landing gear door actuating system parts other than the actuator. Excludes door structure and hinges, which are to be filed in JASC code 5280. Typical parts are bellcrank, rod, sequence valve, latch, lines, hoses, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3232', '32', 'Landing Gear Door Actuator', 'The actuating units that open and close the landing gear doors. Position on the aircraft (nose, left, or right main) should be shown in the "Part Location" field.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3233', '32', 'Landing Gear Actuator', 'The actuating units which retract and extend the nose or main gear. This includes electric motors, hydraulic cylinders but not self-contained electric motor driven hydraulic pumps such as power packs, which are filed in JASC code 2913. Specify “main gear” or “nose gear” in the Location data field.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3234', '32', 'Landing Gear Selector', 'The selector valves, switches, or control levers used to direct a power source to actuators for gear retraction and extension.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3240', '32', 'Landing Gear Brake System', 'The brake system miscellaneous parts other than the brake assembly, master cylinder, power valve and anti-skid system. Includes the pressure source and associated system for emergency brake actuation, and brake anti-ice system. Typical parts are line, hose, fitting, park brake valve, gauge, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3241', '32', 'Brake Anti-Skid Section', 'The system units and parts that automatically control brake pressure during landing roll to prevent tire skidding. Typical parts are transducer, control box, valve, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3242', '32', 'Brake', 'The parts of the brake unit mounted at the wheels only. The position on the aircraft should be shown in the "Part Location" field. Typical parts are disc, cylinder, lining, seal, rotor, housing, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3243', '32', 'Master Cylinder/Brake Valve', 'The units that provide a power source for cylinder-power brake actuation. Does not include connecting lines to brake units, which are filed in JASC code 3240. Typical parts are seal, piston, housing, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3244', '32', 'Tire', 'For reports of tire defects and failures. Include the manufacturer size and defect location in text. Identify the location of the tire in the "Part Location" field (i.e., nose, right main landing gear, "NLG", or "RT MLG").', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3245', '32', 'Tire Tube', 'For reports of defective wheel tire tubes. Include the manufacturer name, tube type and size.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3246', '32', 'Wheel/Ski/Float', 'For reports of defective wheels, skis or seaplane floats and associated parts such as bearings, dust seals, bolts. The "Part Name" field should not refer to a part of the wheel which is defective such as "rim" or "half" that does not have separate part numbers. Such entries should be placed in the text. Identify the location of the wheel in the "Part Location" field (i.e., nose, right main landing gear, "NLG,"or "RT MLG"). The wheel, ski or float make, model, and part number should also be included in the report.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3250', '32', 'Landing Gear Steering System', 'The miscellaneous system parts other than the actuator, which provide for aircraft directional control on the ground. Includes main gear steering systems. Does not include wheel-braking systems. Typical parts are, cable, rod end, collar, line, valve, accumulator, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3251', '32', 'Steering Unit', 'The actuator which turn the wheel(s) by a power source for controlling direction of movement on the ground. Typical parts are cylinder, seal, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3252', '32', 'Shimmy Damper', 'The devices mounted on steerable wheel forks to reduce shimmy. Typical parts are seal, spring, housing, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3260', '32', 'Landing Gear Position and Warning', 'The system parts which provide indication and warning of the landing gear position. Includes gear safety switches which prevent inadvertent actuation such as squat or air/ground sensor. Typical parts are relay, switch bracket, lamp, horn, uplock switch, downlock switch, in transit switch, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3270', '32', 'Auxiliary Gear (Tail Skid)', 'The devices such as tail skids on tricycle gear aircraft used to stabilize the aircraft on the ground and to prevent ground contact damage. This code is also used for supplementary wheels on rotorcraft, skids for ground handling but not for skids or amphibian/seaplane floats, hull or associated retractable landing gear. This code is not for auxiliary or emergency landing gear extension systems which are filed in JASC code 3230.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3297', '32', 'Landing Gear System Wiring', 'For reports indicating a problem with wiring specific to the Landing Gear System.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3300', '33', 'Lighting System', 'The units and components which provide for external and internal illumination. Includes light fixtures, switches and wiring. Does not include warning lights for individual systems. Use this code for reports of a general nature or for miscellaneous external and internal lamps, circuitry, switches, etc., with insufficient information to file in a specific JASC 3300 series code. Warning lights are filed in the individual JASC Chapter 33 code.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3310', '33', 'Flight Compartment Lighting', 'The lighting systems and equipment including panel illumination other than inside individual instruments, master warning light systems such as annunciator panels, and associated dimming systems located in the flight compartment only. Typical parts are bulb, socket, switch, lamp, lens, relay, rheostat, resistor, ballast, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3320', '33', 'Passenger Compartment Lighting', 'The lighting systems in the passenger seating compartment, lavatories, buffet/galley compartments and cabin carry-on baggage/coat areas. Includes lamps for illumination of cabin, reading lamps, seat belt/no-smoking signs and passenger call systems. Does not include emergency lighting which is to be filed in JASC code 3350. Typical parts are ballast, switch, transformer, lamp, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3330', '33', 'Cargo Compartment Lighting', 'The lighting systems in the compartments used for storage of cargo, baggage, or aircraft system components which require servicing. Does not include electrical systems fire or smoke sensing. Typical parts are circuit breaker, lamp, lens, switch, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3340', '33', 'Exterior Lighting', 'The lighting systems for illumination outside the aircraft such as landing, taxi, position, wing illumination including the rotating beacon and strobe. Typical parts are switch, lamp, power supply, lens, circuit breaker, flasher unit, relay, motor, wheel well lights, brackets, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3350', '33', 'Emergency Lighting', 'The cabin, flight compartment, and exterior emergency lighting systems, which furnish illumination in event of electrical power failure. This includes batteries, lamps, and associated circuitry and parts for emergency exit lighting.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3397', '33', 'Light System Wiring', 'For reports indicating a problem with wiring specific to the Lighting Systems.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3400', '34', 'Navigation System', 'The units and components which provide aircraft navigational information. For reports which are of a general nature relating to the navigation systems. Also, for reports on equipment utilized in the flight inspection of airways systems (excluding avionics equipment normally used for flight operations of the aircraft). Use this code for reports with insufficient information to file in a more specific JASC 3400 series code. Typical flight inspection equipment would be computers, recorders, nav comms, guidance equipment, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3410', '34', 'Flight Environment Data', 'The system which senses environmental conditions and uses the data to influence navigation.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3411', '34', 'Pitot/Static System', 'The system which provides a source of ram or static air for distribution to using instruments and pressure differential units such as automatic landing gear extender, altimeter, airspeed and rate of climb. Does not include the using units, instruments, the anti-ice heating elements, or the associated circuitry and switches which are filed in JASC code 3030. Typical parts are air pick up heads, lines, fittings, drain valves, static port, selector valve, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3412', '34', 'Outside Air Temperature Indicator/Sensor', 'The unit mounted in the engine induction air intake to sense and transmit temperature to the cockpit indicator. Also for the sensors and instruments which measure and indicate the temperature of ambient air outside the aircraft. Includes associated circuitry and related parts. Typical parts are sensor, indicator, case, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3413', '34', 'Rate of Climb Indicator', 'The instrument which senses and indicates the rate of climb or descent of an aircraft. Does not include the associated static system. Includes the instantaneous vertical speed indicator (IVSI).', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3414', '34', 'Airspeed/Mach Indicator', 'The instrument which measures and indicates speed of the aircraft. Does not include the Doppler indicator which are filed in JASC code 3443.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3415', '34', 'High Speed Warning', 'The system components and parts, including the computer which sense, transmit and provide warning when operating air speed limits are exceeded. Typical parts are transducer, stall warning detector, switch, vane, horn, lamp, warning unit computer, module, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3416', '34', 'Altimeter, Barometric/Encoder', 'Altimeters and barometric encoders used to measure and indicate altitude. Also includes the unit which senses and alerts to a change in a preselected altitude. Does not include the Ground Proximity Systems and radio/radar altimeters which are filed in JASC codes 3444. Typical parts are dial, case, pointer, spring, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3417', '34', 'Air Data Computer', 'The computer and its integral parts which receives data from various environmental sensing systems, computes this data, and makes it available to the various navigation systems. Does not include external hardware such as cables, mounting racks, remote switches, etc., which are filed in JASC code 3410.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3418', '34', 'Stall Warning System', 'The system components and parts, including the computer which sense, transmit and provide aural, visual and stick shaker warning of an aircraft in an impending flight stall condition. Typical parts are transducer, stall warning detector, switch, vane, horn, lamp, stick shaker, heater element, warning unit computer, module, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3420', '34', 'Attitude and Direction Data System', 'The system components and parts which use magnetic, gyroscopic, and inertia forces to indicate an aircraft attitude and direction. Use this code for reports with insufficient information to file in JASC codes 3421 through 3425. Includes such items as the inertial reference system (IRS), etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3421', '34', 'Attitude Gyro and Indicating System', 'The gyroscopic unit which supplies attitude information to the necessary systems; for instance, vertical reference outputs for use as roll and pitch data to the autopilot computer. Includes the instruments operating by the gyroscopic principle, driven by air flow or an electric motor. Typical parts are vertical gyro and the gyro horizon.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3422', '34', 'Directional Gyro and Indicating System', 'The unit operating by gyroscopic principle and driven by airflow or an electric motor, which provides heading (direction) references relative to a preset heading in degrees of the compass. Also for the flux unit detector which senses the earth''s magnetic field and uses this data to correct for gyro drift. Typical parts are gyro, rotor, bearing, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3423', '34', 'Magnetic Compass', 'The instrument which indicates the magnetic heading of an aircraft by self contained magnetized needles. Typical parts are compensator, adjusting screw, gasket, float, case, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3424', '34', 'Turn and Bank/Rate of Turn Indicator', 'The instrument actuated by gyroscopic forces and driven by air flow or electric motor to indicate both rate of turn and angle of bank.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3425', '34', 'Integrated Flight System', 'The system which computes, interrogates, and continuously displays basic attitude, position, and steering information in order to maintain a particular course, heading, or attitude. Does not include flight management system components, which should be assigned to JASC code 3460. Typical parts are integrated flight annunciator, integrated flight comparator, integrated flight computer/amplifier, integrated flight control and integrated flight indicators (i.e., horizontal situation indicator (HSI), attitude and direction indicator (ADI), attitude direction unit (ADU), heading and direction indicator (HDI), radio direction indicator (RDI), course direction indicator (CDI), flight director indicator (FDI), pictorial navigation indicator, flight command indicator, steering computer utilized in the integrated flight instrument systems, and other components such as cables, connectors, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3430', '34', 'Landing and Taxi Aids', 'The system providing guidance during approach, landing and taxiing. Includes such items as, ILS, paravisual director, ground guidance systems, markers, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3431', '34', 'Localizer/VOR System', 'The electronic portion of an instrument landing system (ILS) that indicates the centerline of the runway to the pilot. For reports on localizer/very high frequency omni range (VOR) systems. Typical parts are receiver, antenna, indicator, circuit breaker, switch, antenna coax, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3432', '34', 'Glide Slope System', 'The system which provides an instrument needle reference from an electronic signal radiated from a ground transmitter to enable the pilot to fly the proper glide path for landing under instrument meteorological conditions. Typical parts are circuit breaker, switch, receiver, antenna, indicator, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3433', '34', 'Microwave Landing System', 'The instrumental landing system operating in the microwave spectrum which provides lateral and vertical guidance to aircraft having compatible avionics equipment. Typical parts are receiver, antenna, control panel, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3434', '34', 'Marker Beacon System', 'The system which provides an aural and visual indication of passage over specified points on the glide path for landing under instrument meteorological conditions. NOTE: In instances where the control panel is an integral portion of the audio control panel, it would be filed in JASC code 2350. Typical parts are marker beacon antenna, receivers, visual/aural indication units, marker light, control panel, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3435', '34', 'Heads Up Display System', 'The flight instrument system that allows the pilot of an aircraft to watch the flight instruments while looking ahead of the aircraft. Includes the display screen which allows information to be visually presented to the pilot while looking through the windscreen or at the control panel.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3436', '34', 'Wind Shear Detection System', 'The flight instrument system that allows the pilot to detect strong horizontal or vertical wind shift that acts at right angles to the direction the wind is blowing. Includes the outboard sensors, indicators, and the warning system which notifies the pilot of the appropriate corrective action maneuver to take.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3440', '34', 'Independent Position Determining System', 'The system which provides information to determine position and is primarily independent of ground installations. Use this code for reports of a general nature or for reports containing insufficient information to file in a more specific code identified in JASC codes 3441 through 3446. Typical parts are star tracker, sextants/octants, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3441', '34', 'Inertial Guidance System', 'The navigation system which relies upon gyro platforms and accelerometers for its operation. Includes the control panel for the inertial navigation system; the instruments which receives their signal from the Inertial Navigation Unit (INU); and the unit containing the inertial platform and digital computer portion of the system. Use this JASC code for hardware components which do not have specific JASC codes assigned to them or when a system malfunction or failure occurs but the exact cause is not known. Typical parts are mode selector unit (MSU), control display unit (CDU), remote display unit (RDU), etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3442', '34', 'Weather Radar System', 'The system components and parts which transmits and receives a signal independent of ground facilities to determine the relative position of adverse weather cells. Typical parts are transceiver, antenna, control panel for the weather avoidance radar system, accessory synchronizers, servo amplifier, scope, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3443', '34', 'Doppler System', 'The airborne radar system which utilizes the Doppler effect to measure and display ground speed, drift angle, cross track, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3444', '34', 'Ground Proximity System', 'The system which detects and alerts flight crew to potential terrain hazards. Includes the antenna which transmits and receives an electronic signal for the radio altimeter equipment used for terrain-to-aircraft distance. Also includes the component which interprets a radio signal reflected back to a receiver to determine distance from the nearest terrain; and the component which process the warning computer input signals from various sources in order to determine if and when the crew should be alerted of a terrain hazard.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3445', '34', 'Air Collision Avoidance System', 'The system which provides information to determine aircraft position and is primarily independent of ground installations (i.e., traffic alert and collision avoidance system - TCAS). Use this code only if the specific system creating the problem cannot be established. Typical parts are collision avoidance monitoring units, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3446', '34', 'Non Radar Weather System', 'The non radar weather system and components which sense the electrostatic charges accumulated around a storm cell in order to "map out" that cell on an indicator.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3450', '34', 'Dependent Position Determining System', 'The system which provides information to determine position and is mainly dependent on ground installations. Use this code for reports of a general nature or for those with insufficient information to file in a more specific JASC code identified in JASC codes 3451 through 3457.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3451', '34', 'DME/TACAN System', 'The systems which measures time-to-station, ground speed, and distance to a known transmitter location by transmitting and receiving electronic pulse signals (i.e., distance measuring equipment - DME; ultra high frequency tactical air navigational aid - TACAN). Typical parts are antenna, control unit, transceiver, coaxial cables, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3452', '34', 'ATC Transponder System', 'The air traffic control (ATC) system which receives coded signals from a ground station and transmits a coded reply for altitude reporting and identification purposes. Typical parts are transponder, antenna, control unit, transceiver, coaxial connecting cables, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3453', '34', 'Long-Range Navigation (LORAN) System', 'The radio navigation system and associated components and parts which provides for long range navigation (LORAN) enroute when operating on signals from ground based master and slave transmitting stations. Typical parts are antenna, coupler, CPU, receiver, indicator, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3454', '34', 'Visual Omnirange (VOR) System', 'The radio navigation system in the very high frequency (VHF) band used for determining position relative to a ground transmitter and permits selection of an infinite number of magnetic courses for navigation to a transmitter (i.e., visual omnirange - VOR system). Typical parts are receiver, antenna, control panel, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3455', '34', 'Automatic Direction Finder (ADF) System', 'The low frequency band system which receives a signal from a non-directional radio beacon to determine relative position from the beacon location (i.e., automatic direction finder - ADF system). Typical parts are antenna, control unit, receiver, coaxial cables, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3456', '34', 'Omega Navigation System', 'The low frequency navigation system which provides for system geographical location of the aircraft on a worldwide basis when operating on signals from ground-based OMEGA and VHF transmitting stations. Typical parts are antenna, control unit or receiver, coaxial connecting cable, remote switches, connectors, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3457', '34', 'Global Positioning System', 'The systems which are mainly dependent upon signals from ground transmitters or orbital satellites for their operations; systems such as VOR, ADF, DME, etc. Use this JASC code when there is insufficient information to assign one of the specific using system codes. Typical parts are antenna, control unit or receiver, coaxial connecting cable, remote switches, connectors, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3460', '34', 'Flight Management Computing Hardware System', 'The hardware systems which combines navigational data to compute or manage the aircraft''s geographical position or theoretical flight path. Typical parts are course computers, flight management computers, performance data computers, and associated control display units, warning annunciators, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3461', '34', 'Flight Management Computing Software System', 'The software system which combines navigational data to compute or manage the aircraft''s geographical position or theoretical flight path.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3497', '34', 'Navigation System Wiring', 'For reports indicating a problem with wiring specific to the Navigation Systems.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3500', '35', 'Oxygen System', 'The units and components which store, regulate, and deliver breathing oxygen to the passengers and crew. Typical parts are bottles, relief valves, shut-off valves, outlets, regulators, masks, walk-around bottles, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3510', '35', 'Crew Oxygen System', 'The portion of the main system which furnishes oxygen to the crew.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3520', '35', 'Passenger Oxygen System', 'The portion of the main system which furnishes oxygen to the passengers.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3530', '35', 'Portable Oxygen System', 'The equipment attached to the portable bottle to regulate and dispense breathing oxygen, including the storage bottle for the portable oxygen system.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3597', '35', 'Oxygen System Wiring', 'For reports indicating a problem with wiring specific to the Oxygen System.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3600', '36', 'Pneumatic System', 'The units and components which deliver large volumes of compressed air from a power source to connecting points for other systems such as air conditioning, pressurization, deicing, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3610', '36', 'Pneumatic Distribution System', 'Components and parts other than the regulator and shutoff valves delivering large volumes of compressed air from a power source to the control valves of using systems such as conditioning, pressurization. Doesn''t include engine and airfoil anti-icing/deicing systems. Typical parts are regulator valve, actuator, duct, ducts valves, manifold, clamp, flow venturi, bellows, wye duct, check valve.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3620', '36', 'Pneumatic Indicating System', 'The system components and parts which sense, transmit, and indicate the temperature and pressure of air in the distribution system other than the pressure indicator or sensor. Includes the instrument which indicates air pressure in the pneumatic distributing systems. Does not include the using systems.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3697', '36', 'Pneumatic System Wiring', 'For reports indicating a problem with wiring specific to the Pneumatic System.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3700', '37', 'Vacuum System', 'The units and components used to generate, deliver, and regulate negative air pressure. Use this code for general reports of the pressure/vacuum system with insufficient information to file in a more specific JASC 3700 series code.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3710', '37', 'Vacuum Distribution System', 'The system components and parts, including the pump, regulator, oil separator or indication system, which are used to distribute low volume, negative pressure air (suction) to systems such as gyroscopic flight instruments, cabin rate controller, etc.; and to distribute low volume, positive pressure air to systems such as air foil deicer boots. Does not include the using systems. Typical parts are pump, filter, regulator, lines, manifold, check valves, element, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3720', '37', 'Vacuum Indicating System', 'The system components and parts including which indicates negative air pressure in the vacuum lines. Includes the indicator and warning systems. Typical parts are the vacuum indicator and associated lines.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3797', '37', 'Vacuum System Wiring', 'For reports indicating a problem with wiring specific to the Vacuum System.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3800', '38', 'Water and Waste System', 'The fixed units and components which store and deliver fresh water. Also includes those fixed components which store and furnish a means of removal of water and waste. Use this code for reports with insufficient information to file in a more specific JASC 3800 series code. This code is also used for reports common to two or more systems.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3810', '38', 'Potable Water System', 'The system which is used to store and deliver fresh drinking water.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3820', '38', 'Wash Water System', 'The system which is used to store and deliver wash water.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3830', '38', 'Waste Disposal System', 'The system and components used for the disposal of water and waste. Includes wash basins, water closets, flush systems and collection tanks. Typical parts are valve, flush motor, lines, timer, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3840', '38', 'Air Supply (Water Pressure System)', 'The system which provides the pressure to distribute potable water to the lavatories, etc. Typical parts are pump, motor, lines, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('3897', '38', 'Water/Waste System Wiring', 'For reports indicating a problem with wiring specific to the Water/Waste System.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('4500', '45', 'Central Maintenance Computer', 'The unit, components and associated systems which interface with other airplane systems and provides a convenient way of communicating system problems to aircraft maintenance personnel. The system contains checkout and fault isolation procedures using a central computer to locate a single system or component malfunction. Typical parts are computer, storage devices, controls, display, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('4597', '45', 'Central Maintenance System Wiring', 'For reports indicating a problem with wiring specific to the Central Maintenance System.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('4900', '49', 'Airborne Auxiliary Power Unit (APU) System', 'The airborne auxiliary power units (APU) installed on aircraft for the purpose of generating and supplying a single type or combination of auxiliary electric, hydraulic, pneumatic or other power. Does not include generators, alternators, hydraulic pumps, etc., or their connecting systems which supply and deliver power to their respective aircraft systems. Use this code for reports of a general nature with insufficient information to file in a specific JASC 4900 series code, or for reports which involve two or more APU systems. An entry "APU" is acceptable if no specific part is reported. The APU as well as aircraft make and model should be reported if known.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('4910', '49', 'APU Cowling/Containment', 'The system of cowling and other components used to cover the auxiliary power unit, and contain any broken parts in the event of an external failure.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('4920', '49', 'APU Core Engine', 'For reports of basic engine defects such as compressor, turbine, cases other than specific systems shown in other APU sub-systems such as fuel, ignition, exhaust, starting and controls. The APU make and model should be included if available. Typical parts are turbine, bearing, seal, impeller, blade, case, burner can, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('4930', '49', 'APU Engine Fuel and Control', 'The system and components which furnishes fuel from the aircraft tanks to the APU fuel control and associated injector nozzles. Including the unit which provides fuel at the proper pressure for fuel control operation; and the unit controlling and injecting metered fuel to the engine burner can section. Typical parts are shutoff valve, line, fitting, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('4940', '49', 'APU Start/Ignition System', 'The system units used to start the APU engine. Including the unit which provides a power source to the igniter during the starting cycle. Typical parts are ignition unit, magneto, igniter, starter, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('4950', '49', 'APU Bleed Air System', 'The system and components which provide and control a source of pressure and high volume of air for aircraft using systems such as engine starting, cabin air conditioning prior to starting engines. Typical parts are duct, bleed valve, clamp, seal, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('4960', '49', 'APU Controls', 'The system components which electrically and manually control operation of the APU engine. Typical parts are relay, control box, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('4970', '49', 'APU Indicating System', 'For general reports of APU operation indicating including the temperature indicator, tachometer generator or indicator (engine speed). Includes the instrument and associated warning system which sense, transmits, and indicates APU engine speed and temperatures to the flight crew.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('4980', '49', 'APU Exhaust System', 'The components and parts which collect and direct exhaust gasses from the APU turbine to the aircraft exterior. Includes the movable door fairing. Typical parts are nozzle, door, actuator, seal, clamp, and shield.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('4990', '49', 'APU Oil System', 'The system and components used for APU engine lubrication. Typical parts are filter, pump, relief valve, hose, line, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('4997', '49', 'APU System Wiring', 'For reports indicating a problem with wiring specific to the APU System.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5100', '51', 'Standard Practices/Structures', 'The standard practices and general procedures for typical repairs applicable to more than one chapter that are not specifically covered under JASC Chapters 52 through 57.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5101', '51', 'Aircraft Structures', 'For reports of aircraft structural problems of a general nature which affects two or more areas. Includes reports of lightning strikes which cannot be associated with a specific JASC code.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5102', '51', 'Balloon Reports', 'For all balloon reports irrespective of location or component involved. Includes all airship reports irrespective of location or component involved. Also includes reports for water ballast. Typical parts are stitching, seam, fabric, burner, valve, handle, valve seat, manifold and burner fuel tank, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5200', '52', 'Doors', 'The removable units used for entrance or exit, and for enclosing other structure contained within the fuselage. Includes passenger and crew doors, cargo doors, emergency exits, etc. Electrical and hydraulic systems associated with door control are included as appropriate. Use this code for door reports of a general nature which affect two or more specific type of doors or are reported with insufficient information to file in a more specific JASC 5200 series code.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5210', '52', 'Passenger/Crew Doors', 'For reports of cabin entrance doors. Does not include door frames, warning systems, or cabin emergency exit doors/hatches. Typical parts are hinges, actuators, latches, handle, seals, structure, spring, cable, bellcrank, skin, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5220', '52', 'Emergency Exits', 'For reports of emergency exit doors, windows and hatches. Typical parts are pan, hinge, latch, hook, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5230', '52', 'Cargo/Baggage Doors', 'For exterior doors used to gain access to cargo or baggage storage areas. Does not include door frames on fuselage, door warning or compartment interior furnishings. Typical parts are door structure, seal, hinge, latch, latch pin, handle, skin, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5240', '52', 'Service Doors', 'For reports pertaining to exterior doors used to gain access for servicing aircraft systems and equipment. Does not include the fluid service doors which are covered in JASC 5246.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5241', '52', 'Galley Doors', 'For reports pertaining to the galley door. Typical parts are hinges, structure, and the latch mechanism.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5242', '52', 'Electrical/Electronic Compartment Doors', 'For reports pertaining to the electrical/electronic compartment doors. Typical parts are hinges, structure, and the latch mechanism.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5243', '52', 'Hydraulic Compartment Doors', 'For reports pertaining to the hydraulic compartment doors. Typical parts are hinges, structure, and the latch mechanism.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5244', '52', 'Accessory Compartment Doors', 'For reports pertaining to the accessory compartment doors. Typical parts are hinges, structure, and the latch mechanism.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5245', '52', 'Air Conditioning Doors', 'For reports pertaining to doors used to gain access to the air conditioning compartment system and components. Typical parts are hinges, structure, and the latch mechanism.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5246', '52', 'Fluid Service Doors', 'For reports of service doors used to gain access to fluid service areas, excluding compartment doors which are filed in JASC code 5243. Typical parts are hinges, structure, and the latch mechanism.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5247', '52', 'Auxiliary Power Unit (APU) Doors', 'For reports of doors used to gain access for servicing the APU and components. Typical parts are hinges, structure, and the latch mechanism.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5248', '52', 'Tail Cone Doors', 'For reports pertaining to the tail cone door. Typical parts are hinges, structure, and the latch mechanism.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5250', '52', 'Fixed Inner Doors', 'For reports of doors within the fuselage in fixed partitions. Typical parts are structure, hinges, latches, lining but does not include doors in movable partitions.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5260', '52', 'Entrance Stairs', 'For reports of cabin entrance stairs which operate in conjunction with but are not an integral part of entrance doors. Typical parts are structure, actuator, controls and handrails, step, cable, bungee, latch hook, latch, bracket, bellcrank, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5270', '52', 'Door Warning System', 'The system which is used to indicate to flight crews whether the exterior doors are closed and properly latched. Does not include the landing gear position warning indications which are covered in JASC code 3260. Typical parts are switch, lamp, horn, relay, etc. The suspect door should be identified if known.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5280', '52', 'Landing Gear Doors', 'For reports pertaining to the structural aspects of landing gear doors including hinges and seals on the wing, landing gear, and fuselage mounted doors. The door position on the aircraft or landing gear (i.e., nose, right main outboard, etc.) should be shown in the part location field. Does not include the operating mechanism or position indicating or warning system which is filed in JASC codes 3231 or 3260.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5297', '52', 'Door System Wiring', 'For reports indicating a problem with wiring specific to the Door Systems.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5300', '53', 'Fuselage Structure (General)', 'For reports of structural units and associated components and members which make up the compartments for crew, passengers, equipment, cargo, plus the structure of the envelope and gondola of airships.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5301', '53', 'Aerial Tow Equipment', 'For reports of defective aerial tow equipment including the attachments on fuselage and release mechanism.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5302', '53', 'Rotorcraft Tail Boom', 'For reports of the structure including exterior skin and truss framework of tail booms on rotorcraft. Includes attach fittings, etc., for tail boom and stabilizer surfaces. Typical parts are bulkhead, bracket, frame, frame tube, plate, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5310', '53', 'Fuselage Main, Structure', 'For general reports of fuselage structure defects which affect two or more related parts or are reported with insufficient information to file in a more specific JASC 5300 series code. Use of this code should be avoided if possible.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5311', '53', 'Fuselage Main, Frame', 'For reports of the main fuselage frames. The associated attach fittings are covered in JASC code 5320.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5312', '53', 'Fuselage Main, Bulkhead', 'For reports of the main fuselage bulkheads and the associated attach fittings.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5313', '53', 'Fuselage Main, Longeron/Stringer', 'For reports of the main fuselage longerons/stringers.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5314', '53', 'Fuselage Main, Keel', 'For reports of the main fuselage keel beams.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5315', '53', 'Fuselage Main, Floor Beam', 'For reports of the main fuselage floor beams.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5320', '53', 'Fuselage Miscellaneous Structure', 'For reports of miscellaneous structure on the main fuselage structure which aids in the support of the primary structure. Includes such items as brackets, channels, stiffeners, clips, doublers, etc. Does not include movable partitions which are covered in JASC Chapter 25.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5321', '53', 'Fuselage Floor Panel', 'For reports of the interior floor panels within the main fuselage structure.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5322', '53', 'Fuselage Internal Mounting Structure', 'For reports of the internal mounting structure which aids in the support of the fuselage structure.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5323', '53', 'Fuselage Internal Stairs', 'For reports of the internal stairs which are part of the fuselage structure.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5324', '53', 'Fuselage Fixed Partitions', 'For reports of the fixed partitions which are part of the fuselage structure.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5330', '53', 'Fuselage Main, Plate/Skin', 'For reports of the exterior covering of the fuselage including access covers.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5340', '53', 'Fuselage Main, Attach Fittings', 'For reports of the fittings on the fuselage used for the attachment of doors, wings, stabilizers, landing gear, engine and rotor pylons, and the support of equipment within the fuselage. For reports of fuselage attach fittings that can not be specifically identified in JASC codes 5341 through 5347.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5341', '53', 'Fuselage, Wing Attach Fittings', 'For reports of the fittings on the fuselage used for the attachment of the wings.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5342', '53', 'Fuselage, Stabilizer Attach Fittings', 'For reports of the fittings on the fuselage used for the attachment of the stabilizers', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5343', '53', 'Fuselage, Landing Gear Attach Fittings', 'For reports of the fittings on the fuselage used for the attachment of the landing gear.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5344', '53', 'Fuselage, Door Hinge', 'For reports of the fittings on the fuselage used for the attachment of the doors.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5345', '53', 'Fuselage, Equipment Attach Fittings', 'For reports of the fittings on the fuselage used for the attachment of equipment.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5346', '53', 'Fuselage, Powerplant Attach Fittings', 'For reports of the fittings on the fuselage used for the attachment of the powerplant. (i.e., the center engine on tri-engine airplanes).', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5347', '53', 'Fuselage, Seat/Cargo Attach Fittings', 'For reports of the fittings on the fuselage used for the attachment of seats and cargo restraint mechanisms.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5350', '53', 'Aerodynamic Fairings', 'For reports of all fixed and removable aerodynamic fairings between the fuselage and wing/flap/empennage/pylon/nacelle attach points, tail cones and radomes. Also includes the fairings on rotorcraft tail cones. Typical parts are tail, radome, fairing, stiffener, skin, screw, fillet, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5397', '53', 'Fuselage Main, Bulkhead Fuselage wiring', 'For reports indicating a problem with wiring specific to the Fuselage System.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5400', '54', 'Nacelle/Pylon Structure', 'For reports of structural units and associated components and members which furnish a means of mounting and housing the powerplant or rotor assembly. Includes the structure of powerplant cowling inclusive of the structural portion of the inlet whether or not integral with the aircraft. Structural portions of the exhaust system are excluded where they are not integral with the airframe. Use this code when there is insufficient information to file in a more specific JASC 5400 series code. NOTE: The use of this code should be avoided if possible as a reported defect is not likely to involve both pylon and nacelle.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5410', '54', 'Nacelle/Pylon, Main Frame', 'For reports of the structure which houses and supports powerplants. Includes the firewall and all structure aft on multi-engine aircraft and firewalls on single engine aircraft. Does not include engine mounting or cowling.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5411', '54', 'Nacelle/Pylon, Frame/Spar/Rib', 'For reports pertaining to the main frame, spar, or rib structure on the nacelles or pylons.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5412', '54', 'Nacelle/Pylon, Bulkhead/Firewall', 'For reports pertaining to the bulkhead or firewall structure on the nacelles or pylons which houses and supports the powerplants. Does not include the engine mounting or cowling. Typical parts are firewall, bulkhead, skin, stringer, beam, splice plate, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5413', '54', 'Nacelle/Pylon, Longeron/Stringer', 'For reports pertaining to the longeron or stringer structure on the nacelles or pylons.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5414', '54', 'Nacelle/Pylon, Plate/Skin', 'For reports pertaining to the plates or skins on the nacelles or pylons.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5415', '54', 'Nacelle/Pylon, Attach Fittings', 'For reports on the fittings on the nacelles/pylons used for the attachment to its connecting structure, powerplant, thrust reverser, and for the support of equipment within the nacelle/pylon.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5420', '54', 'Nacelle/Pylon Miscellaneous Structure', 'For reports of miscellaneous structure on the nacelle/pylon structure which aids in the support of the primary structure. Includes such items as brackets, channels, stiffeners, doublers, clips, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5497', '54', 'Nacelle/Pylon System Wiring', 'For reports indicating a problem with wiring specific to the Nacelle/Pylon System.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5500', '55', 'Empennage Structure', 'The horizontal and vertical stabilizers include the structure of the elevator and rudder. For general reports of empennage structure which affect two or more surfaces or are reported with insufficient information to file in a more specific JASC 5500 series code. This code is also used for reports that pertain to flying wires.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5510', '55', 'Horizontal Stabilizer Structure', 'For reports pertaining to the structural aspects of horizontal stabilizer and stabilators or canard. Includes fuselage and boom-to-surface attach fittings. Does not include actuating mechanism filed in JASC code 2742.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5511', '55', 'Horizontal Stabilizer, Spar/Rib', 'For specific reports of spars/ribs on the horizontal stabilizer.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5512', '55', 'Horizontal Stabilizer, Plate/Skin', 'For specific reports of plates/skins on the horizontal stabilizer.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5513', '55', 'Horizontal Stabilizer, Tab Structure', 'For reports pertaining to the structure and attachment of the tab surface mounted on movable stabilizers and stabilators. Includes hinge brackets and bearings/bushings. Does not include the actuating mechanism filed in JASC code 2740. Typical parts are hinge, skin, rib, spar, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5514', '55', 'Horizontal Stabilizer Miscellaneous Structure', 'For reports of miscellaneous structure on the horizontal stabilizer structure which aids in the support of the primary structure. Includes such items as brackets, channels, stiffeners, doublers, clips, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5520', '55', 'Elevator Structure', 'For reports pertaining to the structural aspects of the movable airfoil hinged to the horizontal stabilizer for longitudinal control. Includes the "ruddervator" on V-tail aircraft and balance weights. Does not include the stabilator structure which is filed in JASC code 5510 or the torque tubes which are filed under the actuating mechanism in JASC code 2730. Typical parts are hinge, hinge fittings, bearing, bolt, miscellaneous structure, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5521', '55', 'Elevator, Spar/Rib', 'For specific reports of spars/ribs on the elevator.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5522', '55', 'Elevator, Plate/Skin', 'For specific reports of plates/skins on the elevator.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5523', '55', 'Elevator, Tab Structure', 'For reports pertaining to the structure of elevator trim surfaces hinged to elevators and "ruddervators." Includes hinge fittings and associated bearings and bolts. Does not include actuating mechanism filed in JASC code 2731.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5524', '55', 'Elevator Miscellaneous Structure', 'For reports of miscellaneous structure on the elevator structure which aids in the support of the primary structure. Includes such items as brackets, channels, stiffeners, doublers, clips, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5530', '55', 'Vertical Stabilizer', 'The structural aspects of the fixed vertical surface attached to the fuselage including the dorsal fin.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5531', '55', 'Vertical Stabilizer, Spar/Rib', 'For specific reports of spars or ribs on the vertical stabilizer.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5532', '55', 'Vertical Stabilizer, Plate/Skin', 'For specific reports of plates or skins on the vertical stabilizer.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5533', '55', 'Ventral Structure', 'For reports pertaining to the ventral structure and skin of the ventral fin mounted on the lower, aft fuselage for added directional stability. Typical parts are skin, rib, rivet, and miscellaneous parts, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5534', '55', 'Vertical Stabilizer Miscellaneous Structure', 'For reports of miscellaneous structure on the vertical stabilizer structure which aids in the support of the primary structure. Includes such items as brackets, channels, stiffeners, doublers, clips, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5540', '55', 'Rudder Structure', 'For reports pertaining to the structural aspects of the vertical airfoil hinged to the vertical stabilizer. Does not include the actuators, actuator mechanism or mounting which are filed in JASC code 2720. Typical parts are hinge, hinge fittings, bearing, bolt, miscellaneous structure, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5541', '55', 'Rudder, Spar/Rib', 'For specific reports pertaining to spars or ribs on the rudder structure.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5542', '55', 'Rudder, Plate/Skin', 'For specific reports pertaining to plates or skins on the rudder structure.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5543', '55', 'Rudder, Tab Structure', 'For reports pertaining to the structure of the movable surface hinged to the rudder surface for directional trim. Typical parts are skin, hinge fitting, spar, rib. The actuating mechanism is filed in JASC code 2720.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5544', '55', 'Rudder Miscellaneous Structure', 'For reports of miscellaneous structure on the rudder structure which aids in the support of the primary structure. Includes such items as brackets, channels, stiffeners, doublers, clips, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5550', '55', 'Empennage Flight Control Surfaces, Attach Fittings', 'For miscellaneous reports of fittings on the empennage structure which are used for the support of the flight control, but are not specifically addressed in JASC codes 5551 through 5554.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5551', '55', 'Horizontal Stabilizer, Attach Fittings', 'For specific reports pertaining to the fittings on the horizontal stabilizer which are used to support equipment within the structure.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5552', '55', 'Elevator Tab, Attach Fittings', 'For specific reports pertaining to the fittings on the elevator or elevator tab which are used to support equipment within the structure.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5553', '55', 'Vertical Stabilizer, Attach Fittings', 'For specific reports pertaining to the fittings on the vertical stabilizer which are used to support equipment within the structure.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5554', '55', 'Rudder/Tab, Attach Fittings', 'For specific reports pertaining to the fittings on the rudder or rudder tab, which are used to support equipment within the structure.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5597', '55', 'Stabilizer System Wiring', 'For reports indicating a problem with wiring specific to the Stabilizer Systems.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5600', '56', 'Window/Windshield System', 'For reports pertaining to the fuselage and crew compartment windows inclusive of windshields. For reports of cockpit and cabin window or windshield defects reported with insufficient information to file in a specific JASC 5600 series code.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5610', '56', 'Flight Compartment Windows', 'For reports of all cockpit windows, cockpit overhead canopies, observation windows, and windshield panels in the flight compartment. Includes attachment and sliding feature of sliding windows. For cockpit windows including the breakage of electrically heated windshield panels regardless of cause. Does not include the heating aspects associated circuitry of heated windshields, which is filed in JASC code 3040. Typical parts are windshield, sliding window, seal, frame, panel, latch, hinge, chin bubbles, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5620', '56', 'Passenger Compartment Windows', 'For reports of cabin mounted windows in the passenger compartments. Includes the inner and outer windows, frame attaching hardware, picture windows. Does not include the windows in the escape hatches which are filed in JASC code 5220.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5630', '56', 'Door Windows', 'For reports of windows mounted in doors. Does not include emergency exit windows which are filed in JASC code 5220.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5640', '56', 'Inspection Windows', 'For windows used for examining compartments and equipment in and about the aircraft such as door latches, and cargo bays.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5697', '56', 'Window System Wiring', 'For reports indicating a problem with wiring specific to the Window System.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5700', '57', 'Wing Structure', 'For reports pertaining to the center wing and outer wing structural units and associated components and members which support the aircraft in flight. This code should be used for general reports of the primary wing structure.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5710', '57', 'Wing Main, Frame Structure', 'For general reports of wing structure defects which affect two or more related parts or are reported with insufficient information to file in a more specific 5700 JASC code. Does not include reports pertaining to fuel tank sealing which are filed in JASC code 2810. Excessive use of this code should be avoided if possible.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5711', '57', 'Wing Spar', 'For reports pertaining to the spar in the wing structure.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5712', '57', 'Wing, Rib/Bulkhead', 'For reports pertaining to the ribs/bulkhead in the wing structure.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5713', '57', 'Wing, Longeron/Stringer', 'For reports pertaining to the longerons or stringers in the wing structure.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5714', '57', 'Wing, Center Box', 'For reports pertaining to the center wing box structure.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5720', '57', 'Wing Miscellaneous Structure', 'For reports of the auxiliary or miscellaneous wing structure. Includes the secondary items used for attachment. Does not include reports for plates or skins. Typical parts are wing tip, clips, brackets, channels, angles, stiffeners, doublers, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5730', '57', 'Wing, Plate/Skin', 'For reports of the exterior covering of the wing including the access covers, tip tank fillets, or fairings. Includes the leading edge and trailing edge skin and wing mounted fuel compartment panels.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5740', '57', 'Wing, Attach Fittings', 'The structure on the wing used for the attachment of fuselage, nacelle or pylon, and landing gear to the wing and for the support of equipment within the wing. Use this code for reports of wing attachments that can not be specifically identified in JASC codes 5741 through 5744. Does not include flight control or landing gear actuator support fittings which should be coded in the appropriate JASC 2700 or 3200 series code.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5741', '57', 'Wing, Fuselage Attach Fittings', 'The fittings on the wing used for attachment to the fuselage structure.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5742', '57', 'Wing, Nacelle/Pylon Attach Fittings', 'The fittings on the wing used for attachment to the nacelle/pylon.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5743', '57', 'Wing, Landing Gear Attach Fittings', 'The fittings on the wing used for attachment to the landing gear.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5744', '57', 'Wing, Control Surface Attach Fittings', 'The fittings on the wing used for attachment to the control surface.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5750', '57', 'Wing, Control Surfaces', 'For reports of a general nature involving the control surfaces which are attached to the wing.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5751', '57', 'Ailerons', 'For reports pertaining to the structural aspects of the aileron mounted on the trailing edge of wing. Includes hinges, balance weights. Does not include operating mechanism which causes the surface to move which is filed in JASC code 2710. Typical parts are skin, rib, spar, hinge, bracket, bolt, bearing, bushing, balance weight, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5752', '57', 'Aileron Tabs', 'For reports pertaining to the structural aspects of the surface mounted at the trailing edge of the aileron for lateral trim. Does not include the operating mechanism filed in JASC code 2711. Typical parts are spar, skin, hinge, bracket, bolt, bearing, bushing.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5753', '57', 'Trailing Edge Flaps', 'For reports pertaining to the structural aspects of the flap surface mounted on the trailing edge of the wing (includes fore, mid, and aft segments). Does not include the operating mechanism such as the actuators, brackets, hydraulic or electric motors. Typical parts are skin, rib, spar, flap track, roller, flap carriage, bearing, bolt, rivet, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5754', '57', 'Leading Edge Devices', 'For reports pertaining to the structural aspects of the wing leading edge device control surface. Includes hinge, brackets, bolts but does not include actuators or actuator mounting brackets which are filed in JASC code 2782. Typical parts are skin, rib, track, roller, bearing, carriage, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5755', '57', 'Spoilers', 'For reports pertaining to the structural aspects of the movable surface on the upper surface of the wing for drag and lift reducing functions. Does not include operating mechanism such as actuators, hoses, lines which are filed in JASC codes 2760 and 2761. Typical parts are skin, rib, gusset plate, spoiler and actuator support fittings.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('5797', '57', 'Wing System Wiring', 'For reports indicating a problem with wiring specific to the Wing Systems. PROPELLER/ROTOR SYSTEMS', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6100', '61', 'Propeller System', 'The complete mechanical or electrical propeller, governor, alternators, pumps, motors those units and components external to or integral with the engine used to control the propeller blade angle. Includes the propulsor duct assemblies, aerodynamic fairing of mechanical components, stators, vectoring systems, etc. Use this code for reports with insufficient information to file in a more specific JASC 6100 series code.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, TRUE, TRUE, FALSE, TRUE, TRUE, TRUE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6110', '61', 'Propeller Assembly', 'For reports of propeller assembly malfunctions excluding controlling aspects, with insufficient information to file in a more specific JASC 6100 series code, or for conditions which affect two or more parts of the propeller such as hub and blades. Includes the propeller retaining nut, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, TRUE, TRUE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6111', '61', 'Propeller Blade Section', 'For reports of blade defects other than deice boots. Includes retaining clamps and blade pitch change actuating mechanism which rotates with the propeller. Typical parts are blade, clamp, link, motor, counterweight, bearing, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, TRUE, TRUE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6112', '61', 'Propeller Deice Boot Section', 'For reports of defective deice/anti-ice system parts on the rotating parts of the propeller such as blades or spinner. Does not include the power source, controls or other non-rotating system parts in JASC code 3060. Typical parts are boot, cuff, heat element, slip ring, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, TRUE, TRUE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6113', '61', 'Propeller Spinner Section', 'For reports of defective propeller spinner assemblies. Typical parts are shell, backplate, bulkhead, rivets, screw, nut plate, brackets, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, TRUE, TRUE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6114', '61', 'Propeller Hub Section', 'For reports of defective hubs which house and support the rotating blades. Includes the dome, but not the blade actuating mechanism filed in JASC code 6111 or the attachment to engine flange in JASC code 6110.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, TRUE, TRUE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6120', '61', 'Propeller Controlling System', 'For general reports of propeller speed controlling other than the governor unit or the synchronizer. Includes the controlling systems of propellers regardless of the propeller type. (Includes propeller regulator, negative torque switch, and the rigging mechanism). Also includes governor control linkage, levers, cable, and associated brackets from the cockpit to the governor; and the feather and unfeathering systems except the pump and accumulator. Typical parts are cable, bellcrank, lever, rod end, pressure switch, solenoid valve, beta switch, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, TRUE, TRUE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6121', '61', 'Propeller Synchronizer Section', 'The unit which controls the synchronization of propellers on multi-engine aircraft. Typical parts are synchronizer actuator, computer, synchrophaser, control unit, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, TRUE, TRUE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6122', '61', 'Propeller Governor', 'The unit which controls the propeller blade angle, but is limited to parts in and on the governor. Does not include airframe furnished control linkage from the cockpit which is filed in JASC code 6120. The component make and model should be included in the report as well as the number of the defective part. Typical parts are shaft, flyweight, governor, spring, arm, seal, beta valve, pilot valve, head, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, TRUE, TRUE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6123', '61', 'Propeller Feathering/Reversing', 'The component and parts which store and deliver an energy charge for propeller feathering and unfeathering. Includes the pump and associated motor, switch, circuitry and plumbing which provides the force for feathering the propeller blades for stopping the engine''s rotation. Does not include propeller feathering system components which are coded in JASC code 6120, such as lever rod end, adjustment screw, solenoid, valves, etc. Typical parts are pump, motor, switch, accumulator, air valve, seal, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, TRUE, TRUE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6130', '61', 'Propeller Braking', 'The system components and parts which decrease run-down time or stop propeller rotation during engine power off conditions. This code is applicable to turboprop engines.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, TRUE, TRUE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6140', '61', 'Propeller Indication System', 'The system components and parts which indicates the operation or activation of propeller systems. Typical parts are switch, lamp, connector, harness, indicator, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, TRUE, TRUE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6197', '61', 'Propeller/Propulsor System Wiring', 'For reports indicating a problem with wiring specific to the Propeller/Propulsor Systems.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, TRUE, TRUE, FALSE, TRUE, TRUE, TRUE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6200', '62', 'Main Rotor System', 'For general reports of rotorcraft main rotor systems with insufficient information to file in a more specific JASC 6200 series code. Excessive use of this code should be avoided if possible.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6210', '62', 'Main Rotor Blades', 'For reports of defective blades including attachment to the rotor head and heating mats on the blades for anti-icing. Also includes tilt rotor blades. Does not include the anti-icing system which is filed in JASC code 3060, or the rotor head which is filed in JASC code 6220. Typical parts are blade, attach bolt, bushing, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6220', '62', 'Main Rotor Head', 'The rotating assembly which supports the main rotor blades including blade folding system. Includes the swashplate if it is an integral part of the mast head assembly. Also includes the head mechanism on tilt rotor aircraft. Typical parts are sleeve, spindle, damper, fairing. Does not include the controlling aspects in JASC code 6710.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6230', '62', 'Main Rotor Mast/Swashplate', 'The vertical shaft which supports the main rotor head. Typical parts are shaft, bearing, guide, mast, seal, swashplate, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6240', '62', 'Main Rotor Indicating System', 'The system used to indicate the operation or activation of the main rotor. Includes lights, gauges, switches, wiring, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6297', '62', 'Main Rotor System Wiring', 'For reports indicating a problem with wiring specific to the Main Rotor System.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6300', '63', 'Main Rotor Drive System', 'For general reports of main rotor drive system with insufficient information to file in a more specific JASC sub-system code. Excessive use of this code should be avoided if possible.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6310', '63', 'Engine/Transmission Coupling', 'The drive shaft between the engine and the main gearbox including the clutch and freewheel units (if applicable), and tilt rotor interconnect system. Typical parts are clutch, shaft, coupling, bearing, boot, seal, sync shaft, pulley, pulley bracket, belt, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6320', '63', 'Main Rotor Gearbox', 'The component which transmits engine power to rotary motion in the main rotor mast. Includes mechanical power take-off and accessory drives but does not include the accessories such as hydraulic pumps and alternators. Includes gearbox lubricating system. Typical parts are gearbox, case, shaft, gear, pump, seal, sun gear, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6321', '63', 'Main Rotor Brake', 'The system which reduces rundown time or stops rotor rotation during engine power off conditions. Typical parts are brake, caliper, lining, seal, check valve, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6322', '63', 'Rotorcraft Cooling Fan System', 'The component which provides a cooling air flow to the rotorcraft piston engine cylinders, oil coolers, etc. Typical parts are fan, shroud, blade, impeller, duct, drive belt, stator, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6330', '63', 'Main Rotor Transmission Mount', 'The suspension system for the transmission mounting in airframe. Typical parts are suspension bars, isolation mount, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6340', '63', 'Rotor Drive Indicating System', 'The indicators, sensors/transmitters and associated systems which indicate operation or activation of rotor systems. Typical parts are tachometer, transmitter, circuit breaker, wiring harness, light, switch, indicator, needle, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6397', '63', 'Main Rotor Drive System Wiring', 'For reports indicating a problem with wiring specific to the Main Rotor Drive System.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6400', '64', 'Tail Rotor System', 'For general reports of the rotorcraft tail rotor system reported with insufficient information to file in a more specific tail rotor system. Avoid excessive use of this code if possible.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6410', '64', 'Tail Rotor Blades', 'For reports of defective tail rotor blades including heating mats for anti-icing but not the anti-icing system in JASC code 3060. Also includes attachment to rotor head. Typical parts are blade, attach bolt, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6420', '64', 'Tail Rotor Head', 'The rotating assembly which supports the tail rotor blades. Does not include the controlling aspects which are filed in JASC code 6720. Typical parts are trunnion, fairing, damper plate, shaft, hub, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6440', '64', 'Tail Rotor Indicating System', 'The indicators, sensors, transmitters, and associated systems which indicates operation or activation of the tail rotor system.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6497', '64', 'Tail Rotor System Wiring', 'For reports indicating a problem with wiring specific to the Tail Rotor System.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6500', '65', 'Tail Rotor Drive System', 'For general reports of the tail rotor drive system reported with insufficient information to file in a more specific tail rotor drive system. Avoid excessive use of this code if possible.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6510', '65', 'Tail Rotor Drive Shaft', 'The shafts, flexible couplings and bearings, etc., from the main rotor transmission to the tail rotor assembly. Typical parts shaft, coupling, bearing, hanger, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6520', '65', 'Tail Rotor Gearbox', 'The gearboxes which transmit engine power to the tail rotor. Includes intermediate gearboxes. Typical parts are case, seal, box, gear, spider gear, gearbox cowling and fairing, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6540', '65', 'Tail Rotor Drive Indicating System', 'The indicators, sensors, transmitters, and associated systems which indicates operation or activation of the tail rotor drive system.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6597', '65', 'Tail Rotor Drive System Wiring', 'For reports indicating a problem with wiring specific to the Tail Rotor Drive System.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6700', '67', 'Rotorcraft Flight Control', 'For general reports of rotorcraft control systems with insufficient information to file in a more specific 6700 JASC series code; or for reports which affect both main and tail rotor control systems. Avoid excessive use of this code if possible.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6710', '67', 'Main Rotor Control', 'The system components and parts other than the servo control system which control and indicates the attitude or the angle of attack of the main rotor blades. Typical parts are collective pitch lever, cyclic pitch stick, coupling and mixing units, and position indicators, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6711', '67', 'Tilt Rotor Flight Control', 'The system components and parts of the tilt rotor control system which controls the attitude of the aircraft by rotating the dual main rotor assembly through a 90-degree position. The zero or vertical position allows vertical takeoff and landing of the aircraft.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6720', '67', 'Tail Rotor Control System', 'The components and system parts which control movement about the vertical axis. The directional control may be accomplished by changing the tail rotor blade angle, or by directed compressed air (i.e., NOTAR systems). Includes tail rotor control pedals, cables, rods, bellcranks, associated support brackets, compressed air ducts, valves, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6730', '67', 'Rotorcraft Servo System', 'The system which ensures distribution of mechanical or electrical power to the rotor servo-control system. Includes systems used to monitor and indicate operation of the servo control system. Typical parts are pressure relief valves, electro valves, check valves, accumulators, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('6797', '67', 'Rotors Flight Control System Wiring', 'For reports indicating a problem with wiring specific to the Rotors Flight Control System. POWERPLANT SYSTEMS', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7100', '71', 'Powerplant System', 'For general reports concerning the powerplant package. Avoid the use of this code if enough information is provided to file in a more specific JASC 7100 series code.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7110', '71', 'Engine Cowling System', 'The enclosure which houses engines for drag reducing and cooling. Includes attachment, structure and access doors. Does not include engine cylinder baffles of fire seals. Typical parts are latch, fastener, lockpin, hook, skin, nose cap, stud, access door, hinge, hinge pin, rivet, bracket, stiffener, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7111', '71', 'Engine Cowl Flaps', 'The flaps mounted in engine cowling for increased cooling air flow. Also includes the component which electrically or hydraulically actuates the cowl flaps. Typical parts are actuator, piston, seal, hinge bracket, skin, doubler, rod, rod end, lever, rivet, bolt, and flap, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7112', '71', 'Engine Air Baffle Section', 'For reports of baffles which direct cooling air flow to the engine cylinders and accessories. Does not include cylinder baffles certificated with the engine which are filed in JASC code 8530. Typical parts are baffle, shield, bracket, shroud, cooling ducts for starters, and generators, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7120', '71', 'Engine Mount Section', 'The structural framework which supports the engine on the nacelle, firewall or pylon. Typical parts are mount, bracket, fitting, shock mount, bolt, isolator, hanger, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7130', '71', 'Engine Fireseals', 'The fire-resistant partitions and seals mounted on or about the power package to isolate areas subject to fire. Does not include firewalls which are filed in JASC code 5412. Typical parts are shroud, bracket, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7160', '71', 'Engine Air Intake System', 'The portion of the powerplant system which directs airflow to the engine. Does not include integral structure with the airframe, which shall be included in the applicable structures JASC chapter. Typical parts are carburetor air heat doors, alternate air doors, linkages, controls, filter element, ducts, hose, air box, latch, seals, nose ring cowls, scoops, compressor fan cowls, compressor fan case, buried engine ducts, vortex generators, actuators, control handles, cables, wiring, plumbing, doors, warning systems, position indicators, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7170', '71', 'Engine Drains', 'The components and manifold assemblies which are used to drain off excess fluids from the powerplant and its accessories. Includes components that are integral parts of, or fitted to the powerplant cowling. Typical parts are drain line, manifold, flame arrestors, support brackets, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7197', '71', 'Powerplant System Wiring', 'For reports indicating a problem with wiring specific to the Powerplant System.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7200', '72', 'Engine (Turbine/Turboprop)', 'The units and components which are used to induce and convert fuel-air mixture into power, and transmit power to the propeller shaft (if any) and accessory drives. Full identification of the powerplant is required in all reports in JASC series codes 7200 through 8300 to increase the usability of the reports. Use this code for general reports concerning engine problems reported with insufficient information to file in a more specific JASC code. Includes reports pertaining to bird strikes to engines/cowling.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7210', '72', 'Turbine Engine Reduction Gear', 'For reports pertaining to reduction gears, combining gearboxes, propeller drive shafts, and helicopter rotor shafts, which are used to transfer power from turboprop and turboshaft engines, to the propeller or helicopter rotor. Do not use this code for accessory devices attached to reduction gearboxes. Typical parts are shaft, gear, bearing, case, torque piston, transfer tube, chip detector, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7220', '72', 'Turbine Engine Air Inlet Section', 'The engine section through which air enters the compressor section. Typical parts are inlet case, inlet cone, inlet screen, guide vane, inlet scroll, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7230', '72', 'Turbine Engine Compressor Section', 'The engine section where incoming air is compressed. Includes the operation of variable stator blades, linkage to the various valves and sense lines. Typical parts are case, the rotating portion of the compressor, lines, fan blades, disc, bearing, seal, mount, carbon seal, disc tie bolts, shaft, static and variable stator blades, linkage, actuator, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7240', '72', 'Turbine Engine Combustion Section', 'The engine section in which fuel and air are mixed and burned. Typical parts are case, burner can, liner, vane ring, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7250', '72', 'Turbine Section', 'The engine section which contains the turbine disc and associated nozzles and cases. Typical parts are case, disc, blade, nozzle, bearing, bearing cover, power turbine, shaft, tie bolts, seals, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7260', '72', 'Turbine Engine Accessory Drive', 'The engine mounted gearbox which provides mechanical power takeoffs to drive accessories such as pumps, generators, chip detectors. Does not include the remote gearboxes which are filed in JASC code 8300.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7261', '72', 'Turbine Engine Oil System', 'The system components and parts which provide lubricating oil pressure, circulation and scavenging throughout the engine. Does not include externally mounted storage tanks filed in JASC code 7910, coolers in JASC code 7921, or connecting lines in JASC code 7920. Typical parts are relief valve, fitting, seal, pump, screen, filter, seal, check valve, element, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7270', '72', 'Turbine Engine Bypass Section', 'For the non-rotating portion of engine air flow ducting for the prime purpose of adding to engine thrust of turbo-jet engines. Does not include the rotating components such as blades. Typical parts are duct, skin, duct segment, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7297', '72', 'Turbine Engine System Wiring', 'For reports indicating a problem with wiring specific to the Turbine Engine System.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7300', '73', 'Engine Fuel and Control', 'For general reports of turbine or reciprocating engine fuel systems with insufficient information to file in a more specific JASC 7300 series code.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7310', '73', 'Engine Fuel Distribution', 'For components and parts of the engine fuel system from the main quick disconnect fitting or airframe fuel system strainer to the fuel control unit. Does not include the controlling or metering aspects filed in JASC code 7322, or the primer systems in JASC code 2820 on reciprocating engines, or the engine fuel pumps, fuel heater, cooler, divider, or injector nozzle (turbine and piston engines). Typical parts are supply lines, hoses, fuel, filters on turbine engines, shutoff and solenoid valves, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7311', '73', 'Engine Fuel/Oil Cooler', 'The unit in which aircraft fuel flows to cool the turbine engine lubricating oil. Does not include the connecting lines.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7312', '73', 'Fuel Heater', 'The unit which heats fuel flowing to the engine to prevent freezing of entrapped water. Does not include connecting lines or the heat source.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7313', '73', 'Fuel Injector Nozzle', 'The unit which injects metered fuel into piston engine cylinders and burner cans in turbine engines.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7314', '73', 'Engine Fuel Pump', 'For reports pertaining to engine fuel pumps. Typical parts are housing, spring, rocker, pump, diaphragm, shaft, seal, relief valve, regulator, coupling, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7320', '73', 'Fuel Controlling System', 'The system components or parts other than the fuel control, amplifier, computer, carburetor and indication systems which control and deliver metered fuel/air to engine cylinders or turbine engine burner cans. Typical parts are sense line, power and drain valve (P & D valve), drain valve, carburetor inlet temperature sensor, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7321', '73', 'Fuel Control/Turbine Engines', 'The components which electronically control metered fuel flow under infinite temperature, altitude, and barometric pressure conditions. This code is also to be used for turbine engines which utilize electronic and non-electronic fuel controls. Typical parts are computer, amplifier, sync box, CIT sensor, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7322', '73', 'Fuel Control/Reciprocating Engines', 'The component which meters fuel/air mixture for engine combustion on reciprocating engines. This code is to be used for fuel injection systems, carburetor systems or other mechanical fuel metering devices reciprocating engine. The typical parts are carburetor, fuel injector, float, diaphragm, bellows, shaft, venturi, control arm, throttle body, servo, discharge tube, bushing, needle, seat, accelerator pump, pin, bearings, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7323', '73', 'Turbine Governor', 'The component which controls the RPM of turbine engines. Typical parts are governor, shaft, overspeed limiter, topping governor, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7324', '73', 'Fuel Divider', 'The unit in metered fuel lines which directs fuel to individual cylinders or burner cans.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7330', '73', 'Engine Fuel Indicating System', 'For reports of fuel temperature, flow rate, or pressure indicating and warning systems other than the indicators, sensors, and transmitters. Typical parts are line, hose, lamp, bulb, wiring harness, circuit breaker, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7331', '73', 'Fuel Flow Indicating', 'The instrument which indicates the flow rate of metered fuel to the engine. Does not include the transmitter. Typical parts are indicator, power supply, needle, dial, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7332', '73', 'Fuel Pressure Indicating', 'The instrument which indicates the pressure of fuel at the fuel control/carburetor as provided by the engine driven or motor driven pumps. Includes the pressure warning indicating lamps. Typical parts are indicator, bourdon tube, diaphragm, needle, case, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7333', '73', 'Fuel Flow Sensor', 'The unit and associated circuitry and parts which senses and transmits the rate of fuel flow to the cockpit indicator. Typical parts are transmitter, sensor, fitting, connector, transducer, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7334', '73', 'Fuel Pressure Sensor', 'The units which sense and transmit to the cockpit indicator or indicator lamps, the pressure of fuel available at the engine fuel control/carburetor. Includes pressure switch and circuitry for warning indication. Typical parts are transducer, transmitter, switch, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7397', '73', 'Engine Fuel System Wiring', 'For reports indicating a problem with wiring specific to the Engine Fuel System.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7400', '74', 'Ignition System', 'For general reports of ignition problems with insufficient information to file in a more specific JASC 7400 series code.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7410', '74', 'Ignition Power Supply', 'The units and components which generate, control, furnish or distribute an electrical current to ignite the fuel air mixture in cylinders of reciprocating engines or in the combustion chambers or thrust augmentors of turbine engines.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7411', '74', 'Low Tension Coil', 'For reports of magneto coils used on select engines such as the Pratt & Whitney (PWA), Model R2800, to generate a low tension voltage to high tension voltage coil mounted at each engine cylinder. Not generally used on modern light aircraft reciprocating engines.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7412', '74', 'Exciter', 'The unit used with turbine engine ignition systems for starting engines. Typical parts are exciter box, bracket, relay. The component make and model should be included.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7413', '74', 'Induction Vibrator', 'The unit which provides a high tension spark to reciprocating engine spark plugs for starting.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7414', '74', 'Magneto/Distributor', 'The components which generate and distribute a high voltage to spark plugs in reciprocating engines for fuel/air combustion. Typical parts are coil, breaker points, gear, bearing, contact finger, distributor block, frame, impulse coupling, condenser, rotor, cam, electrode, seal, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7420', '74', 'Ignition Harness (Distribution)', 'The high tension insulated wiring from the magneto to the spark plug in reciprocating engines which provides a spark for combustion. For turbine engine, the high tension leads to burner can igniters for used for starting. Typical parts are lead, shielding, sleeve, ignition cable, terminal, ferrule, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7421', '74', 'Spark Plug/Igniter', 'The part which provides the spark in the reciprocating engine cylinders or combustion chamber of turbine engines.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7430', '74', 'Ignition Switching', 'The unit which provides a means of rendering the ignition power supply (magneto) inoperative. Also used to direct electrical current to the magneto switch. Does not include engine cranking which is covered in JASC code 8010. Typical parts are start button (only if associated with a ignition switching discrepancy), switch, back plate, contacts, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7497', '74', 'Ignition System Wiring', 'For reports indicating a problem with wiring specific to the Ignition System.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7500', '75', 'Engine Bleed Air System', 'For general reports of turbine engine compressor bleed air systems used to control the flow of air through the engine, cooling air systems, and heated air for engine anti-icing reported with insufficient information to file in a more specific JASC 7500 series code.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7510', '75', 'Engine Anti-Icing System', 'The engine system components and parts used to eliminate and prevent the formation of ice. Includes the control valve and associated actuator, switch and circuitry which controls the flow of turbine engine compressor bleed air to the engine anti-icing system. Anti-icing reports pertaining to the powerplant cowling are filed in JASC code 3020. Typical parts are control valve, actuator, motor, switch, relay, circuit breaker, hose, manifold, coupling, fuel heat duct, fuel heat valve, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7520', '75', 'Engine Cooling System', 'The portion of the engine compressor bleed air system which is used to ventilate engine compartments and accessories. Does not include the engine bleed control valve which is filed in JASC code 7532. Typical parts are jet pumps, vortex generators, valve, actuator, and associated parts and circuitry used to control bleed air to engine accessory cooling systems.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7530', '75', 'Compressor Bleed Control', 'The system except valve and governor which controls the flow of air through turbine engines. Typical parts are sense line, fittings, cables, sense line filter, speed sense valve, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7531', '75', 'Compressor Bleed Governor', 'The unit controlling relative position of the compressor bleed valve in turbine engines for air flow control.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7532', '75', 'Compressor Bleed Valve', 'The component which releases air from turbine engine compressor sections for air flow control. Typical parts are bleed valve, actuator, check valve, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7540', '75', 'Bleed Air Indicating System', 'The systems which indicate temperature, pressure, control positions and warning indications of turbine engine compressor bleed air systems in turbine engines. Typical parts are transmitter, sensor, indicator, lamp, pressure switch, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7597', '75', 'Engine Bleed Air System Wiring', 'For reports indicating a problem with wiring specific to the Engine Bleed Air System.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7600', '76', 'Engine Controls', 'The controls which govern the operation of the engine. Includes units and components which are interconnected for emergency shutdown. For turboprop engines, includes linkages and controls to the coordinator or equivalent to the propeller governor, fuel control unit or other units being controlled. For reciprocating engines, includes controls for blowers. Does not include units or components which are specifically included in other chapters. For general reports of engine control problems with insufficient information to file in a more specific JASC 7600 series code.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7601', '76', 'Engine Synchronizing', 'The components providing for engine synchronization in multi-engine aircraft.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7602', '76', 'Mixture Control', 'The control for adjusting fuel-air mixture in piston engines. Includes linkage from the cockpit lever to the carburetor or fuel injector servo but does not include the arm on mixture control shafts. Typical parts are cable, rod, bellcrank, rod end, housing, clamp and cockpit control lever/knob.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7603', '76', 'Power Lever', 'The system which provides for control of carburetor or fuel injectors on piston engines; fuel controls or coordinator on turbine engines; and propeller regulator turboprop engines. Typical parts are cable, rod, rod end, bellcrank, bracket, clamp, actuator, shaft, shaft pin, knob, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7620', '76', 'Engine Emergency Shutdown System', 'The system which provides for rapid, complete shutoff of combustible fluids to the engine compartments during emergency procedures. Typical parts are cable, actuator, switch, lever, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7697', '76', 'Engine Control System Wiring', 'For reports indicating a problem with wiring specific to the Engine Control System.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7700', '77', 'Engine Indicating System', 'For general reports of engine indicating system discrepancies with insufficient information to file in a more specific JASC 7700 series code. This code is also used for reports with multiple engine indications.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7710', '77', 'Power Indicating System', 'For power indicating systems which directly or indirectly indicates power or thrust (i.e., brake mean effective pressure {BMEP}, engine pressure ratio {EPR}, RPM, etc.) but is not covered in JASC codes 7711 through 7722.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7711', '77', 'Engine Pressure Ratio (EPR)', 'The system which sense, measures, and indicates the engine pressure ratio (EPR) of an turbine engine. The system measures the difference between the compressor inlet pressure and the turbine discharge pressure. Typical parts are sensor, transducer, transmitter, probe, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7712', '77', 'Engine BMEP/Torque Indicating', 'The system that senses and measures brake mean effective pressure (BMEP) or engine torque in turbo- prop and piston engines. Does not include internal parts which are type certificated with the engine. Typical parts are indicator, line, sensor, transmitter, pressure switch, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7713', '77', 'Manifold Pressure (MP) Indicating', 'The reciprocating engine manifold pressure (MP) indicating system including the indicator and sensor. Typical parts are lines, hoses and fittings.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7714', '77', 'Engine RPM Indicating System', 'The system including the indicator and sensor which indicates engine speed in revolutions per minute (RPM). Typical parts are, cable, connector, tachometer, tachometer generator, N1 indicator.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7720', '77', 'Engine Temperature Indicating System', 'For general reports of the system components and parts which indicate engine temperature with insufficient information to file in a more specific JASC 7700 series code.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7721', '77', 'Cylinder Head Temperature (CHT) Indicating System', 'The instruments which indicates temperature measured at reciprocating engine cylinder heads. Typical parts are indicator, case, dial, needle, thermocouple lead, sensor, and connector, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7722', '77', 'Engine EGT/TIT Indicating System', 'For reports of exhaust gas temperature (EGT) or turbine inlet temperature (TIT) temperature sensing and indicating. Includes the EGT indicators for both reciprocating and turbine engines; and the TIT for turbine engines. Typical parts are wiring, turbine outlet temperature (TOT) indicator, EGT indicator, probe, harness, terminal, connector, indicator, sensor, transducer, transmitter, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7730', '77', 'Engine Ignition Analyzer System', 'For general reports of reciprocating engine ignition analyzer system problems. Typical parts are the amplifier, wiring harness, and sensor, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7731', '77', 'Engine Ignition Analyzer', 'The unit which interprets and indicates by oscilloscope the condition of ignition systems on reciprocating engines.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7732', '77', 'Engine Vibration Analyzer', 'For general reports of the engine vibration analyzer system indicating to the flight crew unusual engine vibration conditions. Typical parts are connector, harness, indicator, monitor, sensor, amplifier, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7740', '77', 'Engine Integrated Instrument System', 'The portion of the system which is an integrated concept that receives engine operating parameters and transmits them to a central processor for cockpit presentation. Typical parts are the display units, transmitters, receivers, computers, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7797', '77', 'Engine Indicating System Wiring', 'For reports indicating a problem with wiring specific to the Engine Indication System.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7800', '78', 'Engine Exhaust System', 'For general reports of engine exhaust system defects with insufficient information to file in a more specific JASC 7800 series code.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7810', '78', 'Engine Collector/Tailpipe/Nozzle', 'That portion of the system which collects the exhaust gases from the cylinders, turbines, or turbochargers and conducts them overboard. Includes variable vanes, or nacelle tailpipes used on turboprop powered aircraft and turbo-shaft powered rotorcraft. Typical parts are tailpipe, cone, nozzel, clamp eyebolt, duct, ejector, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7820', '78', 'Engine Noise Suppressor', 'For general reports of muffler system defects. The component used on reciprocating engines to reduce engine exhaust noise. Does not include the shroud over the muffler used to collect heated fresh air for cabin and carburetor heat filed in JASC code 2140. Includes the clover leaf shaped unit mounted on turbo-jet engine exhaust tailpipes for sound suppression. Typical parts are baffle, and flame tube, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7830', '78', 'Engine Thrust Reverser', 'The airframe furnished system and components mounted at turbo-jet engine exhaust tailpipes, or turbofan engine variable fan reverser components used to direct engine thrust forward for deceleration. Does not include the engine tailpipe. Typical parts are door, flex drive, relay, solenoid, switch, switch arm, bolt, valve, line, deploy line, rail, cable, actuator, actuator rod, connector plug, seal, support, fitting, shaft, link, nozzle, hose, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7897', '78', 'Engine Exhaust System Wiring', 'For reports indicating a problem with wiring specific to the Engine Exhaust System', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7900', '79', 'Engine Oil System (Airframe Furnished)', 'For general reports of system units external to the engine which store and deliver engine lubricating oil to and from both turbine and reciprocating engines with insufficient information to file in a more specific JASC 7900 series code.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7910', '79', 'Engine Oil Storage (Airframe Furnished)', 'The engine oil storage tank furnished by the airframe manufacturer. Includes attached parts such as filler caps, mount brackets, but excludes engine manufacturer furnished tanks, quantity indication systems, and distribution lines. Typical parts are tank, cap, seal, bracket, drain valve, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7920', '79', 'Engine Oil Distribution (Airframe Furnished)', 'The external oil system which distributes engine lubricating oil from the storage tanks to and from the engine. Does not include externally mounted units such as oil coolers, oil filters, shutoff valves. Typical parts are line, hose, coupling, fitting, clamp, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7921', '79', 'Engine Oil Cooler', 'The component and associated parts that cools engine lubricating oil. Includes brackets, outlet doors, scoops, ducts and louvers, but excludes the temperature regulator. Typical parts are cooler, duct, scoop, door, door actuator, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7922', '79', 'Engine Oil Temperature Regulator', 'The unit which is mounted on the airframe oil cooler or the engine for controlling engine lubricating oil temperature. Typical parts are thermostat, thermal valve, regulator, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7923', '79', 'Engine Oil Shutoff Valve', 'The component and associated controls which stop the flow of lubricating oil to the engine for emergency purposes.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7930', '79', 'Engine Oil Indicating System', 'For general reports of engine oil pressure, temperature and quantity and those reports with insufficient information to file in a more specific JASC 7900 series code. Includes oil filter bypass switch, chip detector light, indicators, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7931', '79', 'Engine Oil Pressure', 'The instrument or warning lamp which indicates, senses, or transmits the pressure of engine lubricating oil available at the engine or when the pressure is improper for the conditions. This code is also used for discrepancies invloving oil pressure regulation. Typical parts are transducer, pressure switch, transmitter, pressure regulator, indicator, case, dial, needle, lamp, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7932', '79', 'Engine Oil Quantity', 'The instrument or warning lamp which senses or indicates the quantity of oil in supply tanks or warns of an insufficient quantity. Typical parts are transmitter, indicator, case, lamp, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7933', '79', 'Engine Oil Temperature', 'The instrument which senses and indicates temperature of engine oil. Typical parts are sensor, temperature bulb, case, indicator, needle, dial, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('7997', '79', 'Engine Oil System Wiring', 'For reports indicating a problem with wiring specific to the Engine Oil System.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('8000', '80', 'Engine Starting System', 'The units, components and associated systems used for starting the engine. Includes electrical, inertia air or other starter systems. Does not include ignition systems which are covered in JASC Chapter 74, IGNITION.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('8010', '80', 'Engine Cranking', 'The portion of the system which is used to perform the cranking functions of the starting operation. Typical parts are plumbing, valve, wiring, start switch, relay, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('8011', '80', 'Engine Starter', 'The component used for starting the engines. Includes parts which are separated from the engine during starter removals, but does not include parts within the engine. Does not include the starter- generator which is filed in JASC code 2435. Typical parts are brush, bearing, shaft, clutch, adaptor, backplate, housing, winding, terminal post, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('8012', '80', 'Engine Start Valves/Controls', 'The valves and controls used for starting engines.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('8097', '80', 'Engine Starting System Wiring', 'For reports indicating a problem with wiring specific to the Engine Starting System.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('8100', '81', 'Exhaust Turbine System (Reciprocating)', 'For reports of exhaust turbine systems for reciprocating engines. Includes power recovery turbine assemblies and turbocharger units when external to the engine.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('8110', '81', 'Power Recovery Turbine', 'The turbines which extract energy from the exhaust gases and are coupled to the crankshaft on reciprocating engines. Includes the power recovery turbine unit when external to the engine. The drive shaft, coupling, and gears are filed in JASC code 8540.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('8120', '81', 'Exhaust Turbocharger', 'For reports of airframe or engine manufacturer furnished exhaust driven turbocharger systems including the turbocharger unit, density controller and waste gate valve. Does not include the tailpipe. Typical parts are clamp, coupling, rod end, bracket, hose, scroll, bearing, impeller, shaft, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('8197', '81', 'Turbocharger System Wiring', 'For reports indicating a problem with wiring specific to the Turbocharger System.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('8200', '82', 'Water Injection System', 'The system components and parts which inject a water mixture into induction system of turbine and reciprocating engines. Typical parts are pump, switch, tank, valve, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('8297', '82', 'Water Injection System Wiring', 'For reports indicating a problem with wiring specific to the Water Injkection System.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('8300', '83', 'Accessory Gearboxes', 'The units and components which are remotely installed and connected to the engine by a drive shaft and which does not include those accessory drives which are bolted to and are immediately adjacent to the engine. The latter item should be filed in JASC code 7200. Does not include accessory drives bolted to and adjacent to engine which are normally filed in JASC code 7260.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('8397', '83', 'Accessory Gearbox System Wiring', 'For reports indicating a problem with wiring specific to the Accessory Gearbox.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, FALSE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('8500', '85', 'Engine (Reciprocating)', 'For general reports concerning reciprocating engine problems reported with insufficient information to file in a more specific JASC 8500 series code. Also for reports without reference to the applicable engine section or system. Typical reports would pertain to overtemperature, metal contamination, vibration, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, TRUE, FALSE, FALSE, FALSE, TRUE, TRUE, TRUE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('8510', '85', 'Reciprocating Engine Front Section', 'For reports of the piston engine front cases which contain the propeller shaft, reduction gears, and accessory drive. Typical parts are propeller shaft, gear, bearing, bushing, case, seal, pinion gear.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, TRUE, FALSE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('8520', '85', 'Reciprocating Engine Power Section', 'The section which contains the crankshaft, cam shaft, tappet guides, valve lifters, connecting rods, drive gears, etc. Does not include the push rods which are filed in the cylinder section in JASC code 8530 or rear case accessory drives. Typical parts are crankcase, crankshaft, cam ring, lifter, camshaft, cylinder stud, connecting rod, bolt, through bolt, cap, rod bolt, main bearing, rod bearing, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, TRUE, FALSE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('8530', '85', 'Reciprocating Engine Cylinder Section', 'For reports of engine cylinders and associated parts including the intake pipes and valve push rods/housing. Also includes the cylinder baffles furnished by the engine manufacturer for engine cooling. Does not include the connecting rods or cylinder flange hold down bolts/studs which are in filed JASC code 8520. Typical parts are piston, piston pin, exhaust valve, intake valve, valve guide, rocker arm, valve cover, cylinder, pushrod housing, intake pipe, piston pin plug, valve spring, rocker shaft, piston ring, oil drain lines, clamp, baffles, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, TRUE, FALSE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('8540', '85', 'Reciprocating Engine Rear Section', 'The case or section where accessories and associated engine drives are located. Includes the accessory pads, drives and drive seals but not the accessories. Does not include oil pump, filter or internal lubricating system which are filed in JASC code 8550. Typical parts are seal, gear, drive shaft, case, bearing, spacer. The power recovery turbine (PRT) drive shaft, coupling, and gears are also filed in this code.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, TRUE, FALSE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('8550', '85', 'Reciprocating Engine Oil System', 'The components and parts that provide oil pressure and distribute lubricating oil within the engine. Includes the plumbing leading to and from the using external systems and components which utilize engine system oil for operation. Does not include the externally mounted oil system storage tanks and connecting lines which are filed in JASC code 7910, or the oil cooler lines, hoses, and drain valves in JASC code 7920. Typical parts are pressure and scavenge pump, impeller, housing, filter, air-oil separator, crankcase breather, screen, element, relief valve, drive gear, adapter, pan, dipstick, cap, propeller governor oil lines, etc.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, TRUE, FALSE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('8560', '85', 'Reciprocating Engine Supercharger', 'The components and parts of the Supercharger system. Typical parts are case, impeller, rotors, bearings, seals, belts, pulleys or sprockets. Does not include gears in engine rear section.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, TRUE, FALSE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('8570', '85', 'Reciprocating Engine Liquid Cooling', 'The components and parts that provide cooling liquid to the engine. Includes the plumbing leading to and from the engine. Typical parts are radiator, hoses, pump, drive belt, pulleys, bearings, seals, overflow line, overflow tank, pressure cap, thermostat.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, TRUE, FALSE, FALSE, FALSE, TRUE, TRUE, FALSE, FALSE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.'),
  ('8597', '85', 'Engine System Wiring', 'For reports indicating a problem with wiring specific to the Reciprocating Engine System.', 'FAA Joint Aircraft System/Component Code Table and Definitions', '2008-10-27', 'https://sdrs.faa.gov/documents/JASC_Code.pdf', 'active', TRUE, FALSE, TRUE, FALSE, FALSE, FALSE, TRUE, TRUE, FALSE, TRUE, 'Heuristic applicability; confirm against aircraft IPC/AMM/maintenance manual.')
